export const RUNTIME_FILES: Record<string, string> = {
  "apply.ts": "/**\n * `state apply <script-id> <scene-id> <choice-id>`\n *\n * Core state-transition command. Reads the auto save's current state, locates\n * the choice's consequences from the script, applies each delta through\n * schema-aware semantics, writes the updated state.yaml + meta.yaml atomically.\n * Always operates on the script's auto/ save directory.\n */\n\nimport { applyDelta, type ChangeEntry } from './schema.js'\nimport { loadScriptFile, type ParsedScript } from './script.js'\nimport {\n  resolveSavePaths,\n  resolveScriptPath,\n  readStateFile,\n  readMetaFile,\n  writeSaveTransaction,\n  type MetaFile,\n} from './io.js'\nimport { appendHistory, historyPath } from './history.js'\n\nexport interface ApplyResult {\n  scriptId: string\n  fromScene: string\n  toScene: string\n  choiceId: string\n  changes: ChangeEntry[]\n}\n\nexport function runApply(\n  skillRoot: string,\n  scriptId: string,\n  sceneId: string,\n  choiceId: string\n): ApplyResult {\n  const paths = resolveSavePaths(skillRoot, scriptId)\n\n  const meta = readMetaFile(paths.metaYamlPath)\n  const scriptPath = resolveScriptPath(skillRoot, meta.scriptRef)\n  const script = loadScriptFile(scriptPath)\n  const parsedState = readStateFile(paths.stateYamlPath)\n\n  const scene = script.scenes.get(sceneId)\n  if (!scene) {\n    throw new Error(`scene \"${sceneId}\" not found in script \"${script.id}\"`)\n  }\n  const choice = scene.choices.find((c) => c.id === choiceId)\n  if (!choice) {\n    throw new Error(\n      `scene \"${sceneId}\" has no choice \"${choiceId}\" ` +\n        `(available: ${scene.choices.map((c) => c.id).join(', ')})`\n    )\n  }\n\n  // Apply each consequences entry. Collect change entries for stdout.\n  const working = { ...parsedState.state }\n  const changes: ChangeEntry[] = []\n  for (const [key, rawDelta] of Object.entries(choice.consequences)) {\n    changes.push(applyDelta(script.schema, working, key, rawDelta))\n  }\n\n  // Determine next scene: explicit `next` > first scene-id after the current in source order.\n  const nextScene = resolveNextScene(script, sceneId, choice.next)\n\n  const newMeta: MetaFile = {\n    scriptRef: meta.scriptRef,\n    currentScene: nextScene,\n    lastPlayedAt: new Date().toISOString(),\n  }\n\n  writeSaveTransaction(\n    paths,\n    { currentScene: nextScene, state: working },\n    newMeta\n  )\n\n  // Append to choice history (non-critical, failure is silently ignored)\n  appendHistory(historyPath(paths.stateYamlPath), sceneId, choiceId)\n\n  return {\n    scriptId: meta.scriptRef,\n    fromScene: sceneId,\n    toScene: nextScene,\n    choiceId,\n    changes,\n  }\n}\n\nfunction resolveNextScene(\n  script: ParsedScript,\n  currentSceneId: string,\n  explicitNext: string | undefined\n): string {\n  if (explicitNext !== undefined) {\n    if (!script.scenes.has(explicitNext)) {\n      throw new Error(\n        `choice.next \"${explicitNext}\" does not exist in script scenes`\n      )\n    }\n    return explicitNext\n  }\n  // Fallback: the next scene in declaration order.\n  const ids = Array.from(script.scenes.keys())\n  const idx = ids.indexOf(currentSceneId)\n  if (idx === -1 || idx === ids.length - 1) {\n    // Staying on the same scene is the safe default when no `next` given and\n    // there's no later scene. Phase 2 should normally hit an ending before this.\n    return currentSceneId\n  }\n  return ids[idx + 1]!\n}\n",
  "history.ts": "/**\n * history.log — append-only record of player choices.\n *\n * Format: one line per choice, `<scene-id>:<choice-id>\\n`.\n * Lives alongside state.yaml and meta.yaml in the save directory.\n */\n\nimport { readFileSync, appendFileSync, writeFileSync, copyFileSync, existsSync } from 'node:fs'\nimport { join, dirname } from 'node:path'\nimport { mkdirSync } from 'node:fs'\n\nexport interface HistoryEntry {\n  sceneId: string\n  choiceId: string\n}\n\n/**\n * Resolve the history.log path from a save directory (same dir as state.yaml).\n */\nexport function historyPath(stateYamlPath: string): string {\n  return join(dirname(stateYamlPath), 'history.log')\n}\n\n/**\n * Read all history entries. Returns empty array if file doesn't exist.\n */\nexport function readHistory(path: string): HistoryEntry[] {\n  if (!existsSync(path)) return []\n  const text = readFileSync(path, 'utf8')\n  return text\n    .split('\\n')\n    .filter((line) => line.includes(':'))\n    .map((line) => {\n      const sep = line.indexOf(':')\n      return {\n        sceneId: line.slice(0, sep),\n        choiceId: line.slice(sep + 1),\n      }\n    })\n}\n\n/**\n * Append a single choice to history.log. Creates the file if missing.\n * Failures are silently ignored — history is auxiliary data.\n */\nexport function appendHistory(path: string, sceneId: string, choiceId: string): void {\n  try {\n    const dir = dirname(path)\n    if (!existsSync(dir)) mkdirSync(dir, { recursive: true })\n    appendFileSync(path, `${sceneId}:${choiceId}\\n`, 'utf8')\n  } catch {\n    // Silently ignore — history is not critical\n  }\n}\n\n/**\n * Clear history (write empty file). Used by reset.\n */\nexport function clearHistory(path: string): void {\n  try {\n    writeFileSync(path, '', 'utf8')\n  } catch {\n    // ignore\n  }\n}\n\n/**\n * Copy history.log from source to destination. Used by save.\n */\nexport function copyHistory(srcPath: string, destPath: string): void {\n  try {\n    if (!existsSync(srcPath)) {\n      // Source doesn't exist — create empty at dest\n      const dir = dirname(destPath)\n      if (!existsSync(dir)) mkdirSync(dir, { recursive: true })\n      writeFileSync(destPath, '', 'utf8')\n      return\n    }\n    const dir = dirname(destPath)\n    if (!existsSync(dir)) mkdirSync(dir, { recursive: true })\n    copyFileSync(srcPath, destPath)\n  } catch {\n    // ignore\n  }\n}\n\n/**\n * Create an empty history.log. Used by init.\n */\nexport function initHistory(path: string): void {\n  const dir = dirname(path)\n  if (!existsSync(dir)) mkdirSync(dir, { recursive: true })\n  writeFileSync(path, '', 'utf8')\n}\n",
  "init.ts": "/**\n * `state init <script-id>`\n *\n * Reads the script, materializes initial_state into state.yaml, sets\n * meta.yaml.script_ref + current_scene = first scene. Always writes to\n * the script's auto/ save directory.\n */\n\nimport { buildInitialState } from './schema.js'\nimport { loadScriptFile } from './script.js'\nimport {\n  resolveSavePaths,\n  resolveScriptPath,\n  writeSaveTransaction,\n  type MetaFile,\n} from './io.js'\nimport { initHistory, historyPath } from './history.js'\n\nexport interface InitResult {\n  scriptId: string\n  firstScene: string\n  fieldCount: number\n}\n\nexport function runInit(skillRoot: string, scriptId: string): InitResult {\n  const scriptPath = resolveScriptPath(skillRoot, scriptId)\n  const script = loadScriptFile(scriptPath)\n  const paths = resolveSavePaths(skillRoot, script.id)\n\n  const initialState = script.initialState\n  // Defensive check: initial_state must equal schema.keys (strict).\n  const schemaKeys = new Set(Object.keys(script.schema))\n  const initKeys = new Set(Object.keys(initialState))\n  for (const k of schemaKeys) {\n    if (!initKeys.has(k)) {\n      throw new Error(\n        `script.initial_state missing field \"${k}\" (must equal state_schema key set)`\n      )\n    }\n  }\n  for (const k of initKeys) {\n    if (!schemaKeys.has(k)) {\n      throw new Error(\n        `script.initial_state has extra field \"${k}\" not in state_schema`\n      )\n    }\n  }\n\n  const meta: MetaFile = {\n    scriptRef: script.id,\n    currentScene: script.firstSceneId,\n    lastPlayedAt: new Date().toISOString(),\n  }\n\n  writeSaveTransaction(\n    paths,\n    {\n      currentScene: script.firstSceneId,\n      state: { ...initialState },\n    },\n    meta\n  )\n\n  // Create empty history.log for this save\n  initHistory(historyPath(paths.stateYamlPath))\n\n  return {\n    scriptId: script.id,\n    firstScene: script.firstSceneId,\n    fieldCount: Object.keys(initialState).length,\n  }\n}\n\n// Kept exported for tests that want to use initial_state without hitting disk.\nexport { buildInitialState }\n",
  "io.ts": "/**\n * Filesystem IO helpers for skill runtime state files.\n *\n * All writes go through atomicWrite: write to a temp file alongside the\n * target then rename. fs.rename is atomic on POSIX, so a crash anywhere in\n * this sequence leaves the target file in its old state.\n */\n\nimport { readFileSync, writeFileSync, renameSync, mkdirSync, existsSync } from 'node:fs'\nimport { dirname } from 'node:path'\nimport {\n  parseMiniYaml,\n  serializeMiniYaml,\n  type MiniDocument,\n  type MiniBlock,\n} from './mini-yaml.js'\nimport { parseStateFile, type ParsedStateFile, type StateRecord } from './schema.js'\n\nexport type SaveType = 'auto' | { manual: string }\n\nexport interface SavePaths {\n  stateYamlPath: string\n  metaYamlPath: string\n}\n\nexport interface MetaFile {\n  scriptRef: string\n  currentScene: string\n  lastPlayedAt?: string\n  currentRoute?: string\n}\n\n/**\n * Atomic single-file write: write to `<path>.tmp` then rename to `<path>`.\n * The parent directory is created recursively if missing.\n */\nexport function atomicWrite(path: string, content: string): void {\n  const dir = dirname(path)\n  if (!existsSync(dir)) {\n    mkdirSync(dir, { recursive: true })\n  }\n  const tmp = `${path}.tmp.${process.pid}.${Date.now()}`\n  writeFileSync(tmp, content, 'utf8')\n  renameSync(tmp, path)\n}\n\n/**\n * Transactional write of state.yaml + meta.yaml.\n *\n * Both files are written to temp paths first. Only after both temp writes\n * succeed do we rename both into place. If the first rename succeeds and the\n * second fails, we attempt to roll back the first rename (best-effort).\n */\nexport function writeSaveTransaction(\n  paths: SavePaths,\n  state: ParsedStateFile,\n  meta: MetaFile\n): void {\n  const stateText = serializeStateFile(state)\n  const metaText = serializeMetaFile(meta)\n\n  const dir = dirname(paths.stateYamlPath)\n  if (!existsSync(dir)) {\n    mkdirSync(dir, { recursive: true })\n  }\n\n  const stateTmp = `${paths.stateYamlPath}.tmp.${process.pid}.${Date.now()}`\n  const metaTmp = `${paths.metaYamlPath}.tmp.${process.pid}.${Date.now()}`\n\n  writeFileSync(stateTmp, stateText, 'utf8')\n  try {\n    writeFileSync(metaTmp, metaText, 'utf8')\n  } catch (err) {\n    safeUnlink(stateTmp)\n    throw err\n  }\n\n  // Capture old content for rollback (if files already existed)\n  const stateOld = existsSync(paths.stateYamlPath)\n    ? readFileSync(paths.stateYamlPath, 'utf8')\n    : null\n  const metaOld = existsSync(paths.metaYamlPath)\n    ? readFileSync(paths.metaYamlPath, 'utf8')\n    : null\n\n  renameSync(stateTmp, paths.stateYamlPath)\n  try {\n    renameSync(metaTmp, paths.metaYamlPath)\n  } catch (err) {\n    // Rollback state.yaml (best-effort)\n    if (stateOld !== null) {\n      writeFileSync(paths.stateYamlPath, stateOld, 'utf8')\n    }\n    safeUnlink(metaTmp)\n    throw err\n  }\n  // Suppress unused-var lint for metaOld; rollback path is captured via stateOld only\n  void metaOld\n}\n\nfunction safeUnlink(path: string): void {\n  try {\n    const { unlinkSync } = require('node:fs') as typeof import('node:fs')\n    unlinkSync(path)\n  } catch {\n    // ignore\n  }\n}\n\nexport function readStateFile(path: string): ParsedStateFile {\n  const text = readFileSync(path, 'utf8')\n  return parseStateFile(text)\n}\n\nexport function readMetaFile(path: string): MetaFile {\n  const text = readFileSync(path, 'utf8')\n  const doc = parseMiniYaml(text)\n  const scriptRef = doc.script_ref\n  const currentScene = doc.current_scene\n  if (typeof scriptRef !== 'string') {\n    throw new Error('meta.yaml missing script_ref')\n  }\n  if (typeof currentScene !== 'string') {\n    throw new Error('meta.yaml missing current_scene')\n  }\n  const lastPlayedAt = typeof doc.last_played_at === 'string' ? doc.last_played_at : undefined\n  const currentRoute = typeof doc.current_route === 'string' ? doc.current_route : undefined\n  return { scriptRef, currentScene, lastPlayedAt, currentRoute }\n}\n\nexport function serializeStateFile(parsed: ParsedStateFile): string {\n  const doc: MiniDocument = {\n    current_scene: parsed.currentScene,\n    state: { ...parsed.state } as MiniBlock,\n  }\n  return serializeMiniYaml(doc)\n}\n\nexport function serializeMetaFile(meta: MetaFile): string {\n  const doc: MiniDocument = {\n    script_ref: meta.scriptRef,\n    current_scene: meta.currentScene,\n  }\n  if (meta.lastPlayedAt !== undefined) {\n    doc.last_played_at = meta.lastPlayedAt\n  }\n  if (meta.currentRoute !== undefined) {\n    doc.current_route = meta.currentRoute\n  }\n  return serializeMiniYaml(doc)\n}\n\n/**\n * Resolve save paths relative to the skill root. Saves are organized\n * per-script: `runtime/saves/<scriptId>/auto/` for the single auto-save,\n * and `runtime/saves/<scriptId>/manual/<timestamp>/` for manual snapshots.\n */\nexport function resolveSavePaths(skillRoot: string, scriptId: string, saveType: SaveType = 'auto'): SavePaths {\n  const subdir = saveType === 'auto' ? 'auto' : `manual/${saveType.manual}`\n  const base = `${skillRoot}/runtime/saves/${scriptId}/${subdir}`\n  return {\n    stateYamlPath: `${base}/state.yaml`,\n    metaYamlPath: `${base}/meta.yaml`,\n  }\n}\n\n/**\n * Resolve the script file path for a given script id. Strips any `.json` or\n * leading `script-` prefix before rebuilding the canonical form.\n */\nexport function resolveScriptPath(skillRoot: string, scriptId: string): string {\n  let id = scriptId\n  if (id.endsWith('.json')) id = id.slice(0, -5)\n  if (!id.startsWith('script-')) id = `script-${id}`\n  return `${skillRoot}/runtime/scripts/${id}.json`\n}\n\n/**\n * Build the save dir from a SavePaths, for rendering in error messages.\n */\nexport function saveDirOf(paths: SavePaths): string {\n  return dirname(paths.stateYamlPath)\n}\n\n// Re-export StateRecord for convenience in command modules.\nexport type { StateRecord }\n",
  "list.ts": "/**\n * `state list <script-id>`\n *\n * Scans the per-script save directory and returns a JSON summary of all\n * saves (one auto + up to 3 manual snapshots).\n */\n\nimport { existsSync, readdirSync } from 'node:fs'\nimport { join } from 'node:path'\nimport { resolveSavePaths, readMetaFile } from './io.js'\n\nexport interface SaveSummary {\n  currentScene: string\n  lastPlayedAt: string | null\n}\n\nexport interface ManualSaveSummary extends SaveSummary {\n  timestamp: string\n}\n\nexport interface ListResult {\n  scriptId: string\n  auto: SaveSummary | null\n  manual: ManualSaveSummary[]\n}\n\nexport function runList(skillRoot: string, scriptId: string): ListResult {\n  const result: ListResult = {\n    scriptId,\n    auto: null,\n    manual: [],\n  }\n\n  // Check auto save\n  const autoPaths = resolveSavePaths(skillRoot, scriptId, 'auto')\n  if (existsSync(autoPaths.metaYamlPath)) {\n    try {\n      const meta = readMetaFile(autoPaths.metaYamlPath)\n      result.auto = {\n        currentScene: meta.currentScene,\n        lastPlayedAt: meta.lastPlayedAt ?? null,\n      }\n    } catch {\n      // Corrupted auto save — report as null\n    }\n  }\n\n  // Scan manual saves\n  const manualDir = join(skillRoot, 'runtime', 'saves', scriptId, 'manual')\n  if (existsSync(manualDir)) {\n    const entries = readdirSync(manualDir, { withFileTypes: true })\n      .filter((e) => e.isDirectory())\n      .map((e) => e.name)\n      .sort() // lexicographic = chronological for timestamps\n\n    for (const timestamp of entries) {\n      const manualPaths = resolveSavePaths(skillRoot, scriptId, { manual: timestamp })\n      if (existsSync(manualPaths.metaYamlPath)) {\n        try {\n          const meta = readMetaFile(manualPaths.metaYamlPath)\n          result.manual.push({\n            timestamp,\n            currentScene: meta.currentScene,\n            lastPlayedAt: meta.lastPlayedAt ?? null,\n          })\n        } catch {\n          // Skip corrupted manual saves\n        }\n      }\n    }\n  }\n\n  return result\n}\n",
  "main.ts": "#!/usr/bin/env bun\n/**\n * state CLI entry point.\n *\n * Invoked by the soulkiller binary via `soulkiller runtime <subcommand>`\n * (since the skill-runtime-binary change). The binary spawns itself with\n * BUN_BE_BUN=1 and SKILL_ROOT pointing at the installed skill root.\n *\n * SKILL_ROOT defaults to two levels up from this file\n * (runtime/lib/main.ts → skill root) when unset.\n */\n\nimport { dirname, resolve } from 'node:path'\nimport { runInit } from './init.js'\nimport { runApply } from './apply.js'\nimport { runValidate } from './validate.js'\nimport { runRebuild } from './rebuild.js'\nimport { runReset } from './reset.js'\nimport { runList } from './list.js'\nimport { runSave } from './save.js'\nimport { runTree, runTreeStop } from './tree.js'\nimport { AVAILABLE_VIEWS, startServer as startViewerServer } from './viewer-server.js'\nimport { runScriptPlan, runScriptScene, runScriptEnding, runScriptBuild } from './script-builder.js'\nimport { runRoute } from './route.js'\nimport { runScripts } from './scripts.js'\nimport type { ChangeEntry } from './schema.js'\nimport type { SaveType } from './io.js'\n\nconst SUBCOMMANDS = [\n  'doctor',\n  'init',\n  'apply',\n  'validate',\n  'rebuild',\n  'reset',\n  'save',\n  'list',\n  'scripts',\n  'viewer',\n  'viewer-serve',\n  'tree',\n  'script',\n  'route',\n  '--help',\n  '-h',\n] as const\n\nfunction printHelp(): void {\n  process.stdout.write(\n    [\n      'state — Skill runtime state management CLI',\n      '',\n      'Usage:',\n      '  state <subcommand> [args...]',\n      '',\n      'Subcommands:',\n      '  doctor                                         Runtime health check',\n      '  init <script-id>                               Initialize auto save from initial_state',\n      '  apply <script-id> <scene> <choice>             Apply a choice consequences transaction',\n      '  validate <script-id> [<save-type>] [--continue] Return JSON diagnostic (writes nothing)',\n      '  rebuild <script-id> [<save-type>]              Repair state.yaml, preserving valid fields',\n      '  reset <script-id> [<save-type>]                Wholesale reset to initial_state',\n      '  save <script-id> [--overwrite <timestamp>]     Snapshot auto save to manual/',\n      '  list <script-id>                               List all saves for a script (JSON)',\n      '  scripts                                        List all generated scripts (JSON)',\n      '  viewer <view> <script-id>                      Start viewer server (views: tree)',\n      '  tree <script-id>                               Start branch tree visualization server',\n      '  tree --stop                                    Stop the visualization server',\n      '  script plan <id>                               Validate + enrich plan.json',\n      '  script scene <id> <scene-id>                   Validate + promote a scene draft',\n      '  script ending <id> <ending-id>                 Validate + promote an ending draft',\n      '  script build <id>                              Merge plan+scenes+endings into script.json',\n      '  route <script-id> <gate-scene-id>               Evaluate affinity gate routing',\n      '',\n      'Save types: auto (default), manual:<timestamp>',\n      '',\n      'Note: `state get` and `state set` are intentionally not provided.',\n      'Reads go through the host Read tool; writes must go through these semantic commands.',\n      '',\n    ].join('\\n')\n  )\n}\n\nfunction resolveSkillRoot(): string {\n  const envRoot = process.env.SKILL_ROOT\n  if (envRoot !== undefined && envRoot !== '') return envRoot\n  // Fallback: walk up from this file (runtime/lib/main.ts → runtime → skill root)\n  const here = dirname(new URL(import.meta.url).pathname)\n  return resolve(here, '..', '..')\n}\n\nfunction serializeChange(c: ChangeEntry): string {\n  const arrow = `${JSON.stringify(c.oldValue)} → ${JSON.stringify(c.newValue)}`\n  const suffix = c.clamped ? ' (clamped)' : ''\n  return `  ${c.key}  ${arrow}${suffix}`\n}\n\n/**\n * Parse save-type from CLI arg: \"auto\" or \"manual:<timestamp>\".\n */\nfunction parseSaveType(arg: string | undefined): SaveType {\n  if (arg === undefined || arg === 'auto') return 'auto'\n  if (arg.startsWith('manual:')) {\n    return { manual: arg.slice('manual:'.length) }\n  }\n  // If it looks like a flag (--continue), default to auto\n  if (arg.startsWith('--')) return 'auto'\n  return 'auto'\n}\n\nexport async function runCli(argv: string[]): Promise<number> {\n  const sub = argv[0]\n  if (sub === undefined || sub === '--help' || sub === '-h') {\n    printHelp()\n    return 0\n  }\n  if (!SUBCOMMANDS.includes(sub as (typeof SUBCOMMANDS)[number])) {\n    process.stderr.write(\n      `error: unknown subcommand \"${sub}\"\\n` +\n        `all writes must go through init/apply/reset/rebuild; no get/set.\\n` +\n        `run \"state --help\" for the full list.\\n`\n    )\n    return 2\n  }\n\n  const skillRoot = resolveSkillRoot()\n\n  try {\n    if (sub === 'doctor') {\n      // Compat: old skill archives still invoke `soulkiller runtime doctor`\n      // during Phase -1 Step 0. New SKILL.md templates no longer include that\n      // step, but this branch keeps the historical stdout protocol intact so\n      // older skills' LLM parsers don't trip. stderr carries a deprecation\n      // pointer to the top-level `soulkiller doctor` command.\n      process.stdout.write('STATUS: OK\\n')\n      process.stdout.write(`SOULKILLER_VERSION: ${process.env.SOULKILLER_VERSION ?? 'unknown'}\\n`)\n      process.stdout.write(`BUN_VERSION: ${process.versions.bun ?? 'unknown'}\\n`)\n      process.stdout.write(`PLATFORM: ${process.platform}-${process.arch}\\n`)\n      process.stderr.write(\n        \"DEPRECATED: 'soulkiller runtime doctor' is deprecated; use 'soulkiller doctor' instead\\n\"\n      )\n      return 0\n    }\n\n    if (sub === 'init') {\n      const scriptId = argv[1]\n      if (scriptId === undefined) {\n        process.stderr.write('usage: state init <script-id>\\n')\n        return 2\n      }\n      const result = runInit(skillRoot, scriptId)\n      process.stdout.write(\n        `INITIALIZED\\n  script: ${result.scriptId}\\n  first_scene: ${result.firstScene}\\n  fields: ${result.fieldCount}\\n`\n      )\n      return 0\n    }\n\n    if (sub === 'apply') {\n      const scriptId = argv[1]\n      const sceneId = argv[2]\n      const choiceId = argv[3]\n      if (scriptId === undefined || sceneId === undefined || choiceId === undefined) {\n        process.stderr.write('usage: state apply <script-id> <scene-id> <choice-id>\\n')\n        return 2\n      }\n      const result = runApply(skillRoot, scriptId, sceneId, choiceId)\n      const lines: string[] = [\n        `SCENE  ${result.fromScene} → ${result.toScene}`,\n        result.changes.length > 0 ? 'CHANGES' : 'CHANGES (none)',\n      ]\n      for (const c of result.changes) {\n        lines.push(serializeChange(c))\n      }\n      process.stdout.write(lines.join('\\n') + '\\n')\n      return 0\n    }\n\n    if (sub === 'validate') {\n      const scriptId = argv[1]\n      if (scriptId === undefined) {\n        process.stderr.write('usage: state validate <script-id> [<save-type>] [--continue]\\n')\n        return 2\n      }\n      const saveType = parseSaveType(argv[2])\n      const continueGame = argv.includes('--continue')\n      const result = runValidate(skillRoot, scriptId, saveType, { continueGame })\n      process.stdout.write(JSON.stringify(result, null, 2) + '\\n')\n      return result.ok ? 0 : 1\n    }\n\n    if (sub === 'rebuild') {\n      const scriptId = argv[1]\n      if (scriptId === undefined) {\n        process.stderr.write('usage: state rebuild <script-id> [<save-type>]\\n')\n        return 2\n      }\n      const saveType = parseSaveType(argv[2])\n      const result = runRebuild(skillRoot, scriptId, saveType)\n      process.stdout.write(\n        `REBUILT\\n` +\n          `  script: ${result.scriptId}\\n` +\n          `  kept: ${result.keptFields.length}\\n` +\n          `  defaulted: ${result.defaultedFields.length}\\n` +\n          `  dropped: ${result.droppedFields.length}\\n`\n      )\n      if (result.defaultedFields.length > 0) {\n        process.stdout.write(\n          `DEFAULTED_FIELDS\\n${result.defaultedFields.map((k) => `  ${k}`).join('\\n')}\\n`\n        )\n      }\n      return 0\n    }\n\n    if (sub === 'reset') {\n      const scriptId = argv[1]\n      if (scriptId === undefined) {\n        process.stderr.write('usage: state reset <script-id> [<save-type>]\\n')\n        return 2\n      }\n      const saveType = parseSaveType(argv[2])\n      const result = runReset(skillRoot, scriptId, saveType)\n      process.stdout.write(\n        `RESET\\n  script: ${result.scriptId}\\n  first_scene: ${result.firstScene}\\n  fields: ${result.fieldCount}\\n`\n      )\n      return 0\n    }\n\n    if (sub === 'save') {\n      const scriptId = argv[1]\n      if (scriptId === undefined) {\n        process.stderr.write('usage: state save <script-id> [--overwrite <timestamp>]\\n')\n        return 2\n      }\n      const overwriteIdx = argv.indexOf('--overwrite')\n      const overwrite = overwriteIdx >= 0 ? argv[overwriteIdx + 1] : undefined\n      const result = runSave(skillRoot, scriptId, overwrite)\n      process.stdout.write(JSON.stringify(result, null, 2) + '\\n')\n      return result.ok ? 0 : 1\n    }\n\n    if (sub === 'list') {\n      const scriptId = argv[1]\n      if (scriptId === undefined) {\n        process.stderr.write('usage: state list <script-id>\\n')\n        return 2\n      }\n      const result = runList(skillRoot, scriptId)\n      process.stdout.write(JSON.stringify(result, null, 2) + '\\n')\n      return 0\n    }\n\n    if (sub === 'scripts') {\n      const result = runScripts(skillRoot)\n      process.stdout.write(JSON.stringify(result, null, 2) + '\\n')\n      return 0\n    }\n\n    // Internal: viewer-serve runs the HTTP server in-process (called by detached spawn)\n    if (sub === 'viewer-serve') {\n      const viewName = argv[1]\n      const viewScriptId = argv[2]\n      if (!viewName || !viewScriptId) return 2\n      startViewerServer(skillRoot, viewName, viewScriptId)\n      // Keep process alive — startServer starts Bun.serve which keeps the event loop running\n      return new Promise(() => {}) // never resolves\n    }\n\n    if (sub === 'viewer') {\n      const viewName = argv[1]\n      const viewScriptId = argv[2]\n      if (!viewName || !viewScriptId) {\n        process.stderr.write(`usage: state viewer <view-name> <script-id>\\navailable views: ${AVAILABLE_VIEWS.join(', ')}\\n`)\n        return 2\n      }\n      if (!AVAILABLE_VIEWS.includes(viewName)) {\n        process.stderr.write(`error: unknown view \"${viewName}\"\\navailable views: ${AVAILABLE_VIEWS.join(', ')}\\n`)\n        return 2\n      }\n      // Spawn self as a detached viewer-server process.\n      // process.execPath is always the correct entry:\n      //   compiled binary → ~/.soulkiller/bin/soulkiller\n      //   dev mode (via runCli) → bun (but this code path isn't reached in dev)\n      const { spawn } = await import('node:child_process')\n      const spawnArgs = ['runtime', 'viewer-serve', viewName, viewScriptId]\n      return new Promise<number>((resolve) => {\n        const child = spawn(process.execPath, spawnArgs, {\n          env: {\n            ...process.env,\n            SKILL_ROOT: skillRoot,\n            CLAUDE_SKILL_DIR: skillRoot,\n          },\n          stdio: ['ignore', 'pipe', 'pipe'],\n          detached: true,\n        })\n        let output = ''\n        child.stdout!.on('data', (chunk: Buffer) => {\n          output += chunk.toString()\n          const match = output.match(/VIEWER_URL (http:\\/\\/localhost:\\d+)/)\n          if (match) {\n            child.unref()\n            process.stdout.write(`VIEWER_URL ${match[1]}\\n`)\n            process.stdout.write(`VIEWER_PID ${child.pid}\\n`)\n            resolve(0)\n          }\n        })\n        let stderrOutput = ''\n        child.stderr!.on('data', (chunk: Buffer) => { stderrOutput += chunk.toString() })\n        child.on('error', (err) => {\n          process.stderr.write(`error: ${err.message}\\n`)\n          resolve(1)\n        })\n        child.on('exit', (code) => {\n          if (!output.includes('VIEWER_URL')) {\n            if (stderrOutput) process.stderr.write(stderrOutput)\n            process.stderr.write(`error: viewer-server exited with code ${code}\\n`)\n            resolve(1)\n          }\n        })\n        setTimeout(() => {\n          if (!output.includes('VIEWER_URL')) {\n            child.kill()\n            process.stderr.write('error: viewer-server startup timed out\\n')\n            resolve(1)\n          }\n        }, 10000)\n      })\n    }\n\n    if (sub === 'tree') {\n      if (argv[1] === '--stop') {\n        const result = runTreeStop(skillRoot)\n        process.stdout.write(\n          result.action === 'stopped' ? 'TREE_STOPPED\\n' : 'TREE_NOT_RUNNING\\n'\n        )\n        return 0\n      }\n      const scriptId = argv[1]\n      if (scriptId === undefined) {\n        process.stderr.write('usage: state tree <script-id>  or  state tree --stop\\n')\n        return 2\n      }\n      const result = await runTree(skillRoot, scriptId)\n      process.stdout.write(`TREE_URL ${result.url}\\n`)\n      if (result.action === 'started') {\n        process.stdout.write(`TREE_PID ${result.pid}\\n`)\n      }\n      return 0\n    }\n\n    if (sub === 'route') {\n      const scriptId = argv[1]\n      const gateSceneId = argv[2]\n      if (!scriptId || !gateSceneId) {\n        process.stderr.write('usage: state route <script-id> <gate-scene-id>\\n')\n        return 2\n      }\n      const result = runRoute(skillRoot, scriptId, gateSceneId)\n      if (!result.ok) {\n        process.stderr.write(`error: ${result.error}\\n`)\n        return 1\n      }\n      process.stdout.write(`ROUTE ${result.routeId} → ${result.nextScene}\\n`)\n      return 0\n    }\n\n    if (sub === 'script') {\n      const subSub = argv[1]\n      const id = argv[2]\n\n      if (subSub === 'plan') {\n        if (!id) { process.stderr.write('usage: state script plan <id>\\n'); return 2 }\n        const result = runScriptPlan(skillRoot, id)\n        if (!result.ok) { process.stderr.write(`error: ${result.error}\\n`); return 1 }\n        const lines = [\n          'PLAN_OK',\n          `  scenes: ${result.scenes}`,\n          `  fields: ${result.fields}`,\n          `  acts: ${result.acts}`,\n          `  endings: ${result.endings}`,\n          `  generation_order: ${result.generationOrder.join(',')}`,\n          `  convergence_points: ${result.convergencePoints.join(',') || '(none)'}`,\n        ]\n        process.stdout.write(lines.join('\\n') + '\\n')\n        return 0\n      }\n\n      if (subSub === 'scene') {\n        const sceneId = argv[3]\n        if (!id || !sceneId) { process.stderr.write('usage: state script scene <id> <scene-id>\\n'); return 2 }\n        const result = runScriptScene(skillRoot, id, sceneId)\n        if (!result.ok) { process.stderr.write(`error: ${result.error}\\n`); return 1 }\n        process.stdout.write(`SCENE_OK ${result.sceneId} choices=${result.choices} keys=${result.consequenceKeys}\\n`)\n        return 0\n      }\n\n      if (subSub === 'ending') {\n        const endingId = argv[3]\n        if (!id || !endingId) { process.stderr.write('usage: state script ending <id> <ending-id>\\n'); return 2 }\n        const result = runScriptEnding(skillRoot, id, endingId)\n        if (!result.ok) { process.stderr.write(`error: ${result.error}\\n`); return 1 }\n        process.stdout.write(`ENDING_OK ${result.endingId}\\n`)\n        return 0\n      }\n\n      if (subSub === 'build') {\n        if (!id) { process.stderr.write('usage: state script build <id>\\n'); return 2 }\n        const result = runScriptBuild(skillRoot, id)\n        if (!result.ok) { process.stderr.write(`error: ${result.error}\\n`); return 1 }\n        process.stdout.write(`BUILD_OK script-${result.scriptId}.json scenes=${result.scenes} endings=${result.endings} size=${Math.round(result.sizeBytes / 1024)}KB\\n`)\n        return 0\n      }\n\n      process.stderr.write('usage: state script <plan|scene|ending|build> ...\\n')\n      return 2\n    }\n\n    // Unreachable\n    return 2\n  } catch (err) {\n    process.stderr.write(`error: ${(err as Error).message}\\n`)\n    return 1\n  }\n}\n\n// Direct-execution entry (when invoked as `bun main.ts`).\nif (import.meta.main) {\n  const code = await runCli(process.argv.slice(2))\n  process.exit(code)\n}\n",
  "mini-yaml.ts": "/**\n * Mini YAML parser/serializer for skill runtime state files.\n *\n * Handles exactly two shapes:\n *   1. Flat top-level: `key: value` entries (used by meta.yaml)\n *   2. One-level block: `key:` followed by 2-space-indented `\"quoted-key\": value`\n *      entries (used by state.yaml's `state:` block)\n *\n * Explicitly rejects:\n *   - Nesting deeper than one level\n *   - Tabs (spaces only)\n *   - Block scalars, anchors, tags, flow style\n *\n * Zero dependencies. Designed to be shipped inside skill archives and run by\n * bun without any npm install step.\n */\n\nexport type MiniPrimitive = number | boolean | string\nexport type MiniBlock = Record<string, MiniPrimitive>\nexport type MiniValue = MiniPrimitive | MiniBlock\nexport type MiniDocument = Record<string, MiniValue>\n\nexport class MiniYamlError extends Error {\n  constructor(message: string, public readonly line?: number) {\n    super(line !== undefined ? `[line ${line}] ${message}` : message)\n    this.name = 'MiniYamlError'\n  }\n}\n\ninterface ParsedLine {\n  indent: number\n  key: string\n  value: string\n  isBlockStart: boolean\n}\n\nfunction parseLine(raw: string, lineNo: number): ParsedLine | null {\n  // Detect tabs first\n  if (raw.includes('\\t')) {\n    throw new MiniYamlError('tabs not allowed (use spaces)', lineNo)\n  }\n\n  // Measure indentation\n  let i = 0\n  while (i < raw.length && raw[i] === ' ') i++\n  const indent = i\n\n  // Blank line or comment-only line\n  const rest = raw.slice(i)\n  if (rest === '' || rest.startsWith('#')) return null\n\n  // Parse key: possibly double-quoted\n  let key: string\n  if (rest[0] === '\"') {\n    const end = rest.indexOf('\"', 1)\n    if (end === -1) {\n      throw new MiniYamlError('unterminated quoted key', lineNo)\n    }\n    key = rest.slice(1, end)\n    i += end + 1\n  } else {\n    // Bare key: read until colon\n    const colonRel = rest.indexOf(':')\n    if (colonRel === -1) {\n      throw new MiniYamlError(`no colon found in line: \"${raw}\"`, lineNo)\n    }\n    key = rest.slice(0, colonRel).trimEnd()\n    if (key === '') {\n      throw new MiniYamlError('empty key', lineNo)\n    }\n    i += colonRel\n  }\n\n  // Expect colon after key\n  if (raw[i] !== ':') {\n    throw new MiniYamlError(`expected ':' after key \"${key}\"`, lineNo)\n  }\n  i++\n\n  // Skip spaces between colon and value\n  while (i < raw.length && raw[i] === ' ') i++\n\n  // Value is the remainder, trimmed of trailing whitespace\n  const valueRaw = raw.slice(i).replace(/\\s+$/, '')\n  const isBlockStart = valueRaw === ''\n\n  return { indent, key, value: valueRaw, isBlockStart }\n}\n\nfunction parseScalar(raw: string, lineNo: number): MiniPrimitive {\n  // Double-quoted string\n  if (raw.startsWith('\"') && raw.endsWith('\"') && raw.length >= 2) {\n    return raw.slice(1, -1).replace(/\\\\\"/g, '\"')\n  }\n  // Boolean\n  if (raw === 'true') return true\n  if (raw === 'false') return false\n  // Integer\n  if (/^-?\\d+$/.test(raw)) {\n    const n = parseInt(raw, 10)\n    if (!Number.isFinite(n)) {\n      throw new MiniYamlError(`invalid integer: ${raw}`, lineNo)\n    }\n    return n\n  }\n  // Reject floats explicitly to keep the value space tight\n  if (/^-?\\d+\\.\\d+$/.test(raw)) {\n    throw new MiniYamlError(`float values not supported: ${raw}`, lineNo)\n  }\n  // Bare string (enum value, etc.)\n  return raw\n}\n\nexport function parseMiniYaml(text: string): MiniDocument {\n  const lines = text.split('\\n')\n  const result: MiniDocument = {}\n  let currentBlockKey: string | null = null\n  let currentBlock: MiniBlock | null = null\n\n  for (let idx = 0; idx < lines.length; idx++) {\n    const lineNo = idx + 1\n    const parsed = parseLine(lines[idx]!, lineNo)\n    if (parsed === null) continue\n\n    if (parsed.indent === 0) {\n      // Top-level entry: closes any open block\n      currentBlockKey = null\n      currentBlock = null\n\n      if (parsed.key in result) {\n        throw new MiniYamlError(`duplicate key \"${parsed.key}\"`, lineNo)\n      }\n\n      if (parsed.isBlockStart) {\n        currentBlockKey = parsed.key\n        currentBlock = {}\n        result[parsed.key] = currentBlock\n      } else {\n        result[parsed.key] = parseScalar(parsed.value, lineNo)\n      }\n    } else if (parsed.indent === 2) {\n      if (currentBlock === null) {\n        throw new MiniYamlError(\n          'indented entry without parent block',\n          lineNo\n        )\n      }\n      if (parsed.isBlockStart) {\n        throw new MiniYamlError(\n          `nested block not supported at key \"${parsed.key}\"`,\n          lineNo\n        )\n      }\n      if (parsed.key in currentBlock) {\n        throw new MiniYamlError(\n          `duplicate key \"${parsed.key}\" in block \"${currentBlockKey}\"`,\n          lineNo\n        )\n      }\n      currentBlock[parsed.key] = parseScalar(parsed.value, lineNo)\n    } else {\n      throw new MiniYamlError(\n        `unexpected indentation (${parsed.indent}) at key \"${parsed.key}\"`,\n        lineNo\n      )\n    }\n  }\n\n  return result\n}\n\nfunction needsQuoting(value: string): boolean {\n  if (value === '') return true\n  if (value === 'true' || value === 'false') return true\n  if (/^-?\\d+$/.test(value)) return true\n  if (/^-?\\d+\\.\\d+$/.test(value)) return true\n  // Characters that would confuse the parser or break YAML ergonomics\n  if (/[:#\"\\s\\[\\]{},]/.test(value)) return true\n  return false\n}\n\nfunction serializeScalar(value: MiniPrimitive): string {\n  if (typeof value === 'number') {\n    if (!Number.isInteger(value)) {\n      throw new MiniYamlError(`non-integer number: ${value}`)\n    }\n    return String(value)\n  }\n  if (typeof value === 'boolean') {\n    return value ? 'true' : 'false'\n  }\n  if (needsQuoting(value)) {\n    return `\"${value.replace(/\"/g, '\\\\\"')}\"`\n  }\n  return value\n}\n\nfunction isBlock(value: MiniValue): value is MiniBlock {\n  return typeof value === 'object' && value !== null\n}\n\nexport function serializeMiniYaml(doc: MiniDocument): string {\n  const lines: string[] = []\n  for (const [key, value] of Object.entries(doc)) {\n    if (isBlock(value)) {\n      lines.push(`${key}:`)\n      for (const [subKey, subValue] of Object.entries(value)) {\n        lines.push(`  \"${subKey}\": ${serializeScalar(subValue)}`)\n      }\n    } else {\n      lines.push(`${key}: ${serializeScalar(value)}`)\n    }\n  }\n  return lines.join('\\n') + '\\n'\n}\n",
  "rebuild.ts": "/**\n * `state rebuild <script-id> [<save-type>]`\n *\n * Repair-menu command: reconstructs state.yaml from the script's initial_state\n * while preserving any existing values that are still valid under the current\n * schema. Used when state.yaml has drifted (missing fields, extra fields,\n * wrong types).\n *\n * Semantics:\n *   - For each schema field:\n *     - If the old state has a correctly-typed value, keep it\n *     - Otherwise, fall back to schema.default\n *   - Discard any old state fields not in schema\n *   - meta.yaml is updated only with a fresh lastPlayedAt; current_scene and\n *     script_ref are preserved (rebuild is a repair, not a reset)\n */\n\nimport { validateFieldType, type StateRecord } from './schema.js'\nimport { loadScriptFile } from './script.js'\nimport {\n  resolveSavePaths,\n  resolveScriptPath,\n  readStateFile,\n  readMetaFile,\n  writeSaveTransaction,\n  type MetaFile,\n  type SaveType,\n} from './io.js'\nimport { existsSync } from 'node:fs'\n\nexport interface RebuildResult {\n  scriptId: string\n  keptFields: string[]\n  defaultedFields: string[]\n  droppedFields: string[]\n}\n\nexport function runRebuild(skillRoot: string, scriptId: string, saveType: SaveType = 'auto'): RebuildResult {\n  const paths = resolveSavePaths(skillRoot, scriptId, saveType)\n\n  const meta = readMetaFile(paths.metaYamlPath)\n  const scriptPath = resolveScriptPath(skillRoot, meta.scriptRef)\n  const script = loadScriptFile(scriptPath)\n\n  let prevState: StateRecord = {}\n  let currentScene = meta.currentScene\n  if (existsSync(paths.stateYamlPath)) {\n    try {\n      const parsed = readStateFile(paths.stateYamlPath)\n      prevState = parsed.state\n      currentScene = parsed.currentScene\n    } catch {\n      // Unparseable state.yaml — fall back to pure initial_state\n      prevState = {}\n    }\n  }\n\n  const repaired: StateRecord = {}\n  const kept: string[] = []\n  const defaulted: string[] = []\n  const dropped: string[] = []\n\n  for (const [key, field] of Object.entries(script.schema)) {\n    const oldValue = prevState[key]\n    if (oldValue !== undefined && validateFieldType(field, oldValue)) {\n      repaired[key] = oldValue\n      kept.push(key)\n    } else {\n      repaired[key] = field.default\n      defaulted.push(key)\n    }\n  }\n\n  for (const key of Object.keys(prevState)) {\n    if (!(key in script.schema)) {\n      dropped.push(key)\n    }\n  }\n\n  const newMeta: MetaFile = {\n    scriptRef: meta.scriptRef,\n    currentScene,\n    lastPlayedAt: new Date().toISOString(),\n  }\n\n  writeSaveTransaction(\n    paths,\n    { currentScene, state: repaired },\n    newMeta\n  )\n\n  return {\n    scriptId: script.id,\n    keptFields: kept,\n    defaultedFields: defaulted,\n    droppedFields: dropped,\n  }\n}\n",
  "reset.ts": "/**\n * `state reset <script-id> [<save-type>]`\n *\n * \"从头再来\" — wholesale reset of the save to the script's initial_state.\n * current_scene is reset to the first scene in declaration order. script_ref\n * stays the same (reset stays on the current script; use init for a new one).\n */\n\nimport { loadScriptFile } from './script.js'\nimport {\n  resolveSavePaths,\n  resolveScriptPath,\n  readMetaFile,\n  writeSaveTransaction,\n  type MetaFile,\n  type SaveType,\n} from './io.js'\nimport { clearHistory, historyPath } from './history.js'\n\nexport interface ResetResult {\n  scriptId: string\n  firstScene: string\n  fieldCount: number\n}\n\nexport function runReset(skillRoot: string, scriptId: string, saveType: SaveType = 'auto'): ResetResult {\n  const paths = resolveSavePaths(skillRoot, scriptId, saveType)\n  const meta = readMetaFile(paths.metaYamlPath)\n  const scriptPath = resolveScriptPath(skillRoot, meta.scriptRef)\n  const script = loadScriptFile(scriptPath)\n\n  const newMeta: MetaFile = {\n    scriptRef: script.id,\n    currentScene: script.firstSceneId,\n    lastPlayedAt: new Date().toISOString(),\n  }\n\n  writeSaveTransaction(\n    paths,\n    {\n      currentScene: script.firstSceneId,\n      state: { ...script.initialState },\n    },\n    newMeta\n  )\n\n  // Clear choice history\n  clearHistory(historyPath(paths.stateYamlPath))\n\n  return {\n    scriptId: script.id,\n    firstScene: script.firstSceneId,\n    fieldCount: Object.keys(script.initialState).length,\n  }\n}\n",
  "route.ts": "/**\n * `state route <script-id> <gate-scene-id>`\n *\n * Evaluates an affinity_gate scene's routing conditions against current state.\n * Outputs the matched route and next scene. Writes current_route to meta.yaml.\n */\n\nimport { loadScriptFile } from './script.js'\nimport {\n  resolveSavePaths,\n  resolveScriptPath,\n  readStateFile,\n  readMetaFile,\n  atomicWrite,\n  serializeMetaFile,\n  type MetaFile,\n} from './io.js'\nimport type { StateRecord } from './schema.js'\n\n// ── Condition DSL evaluator ─────────────────────────────────────\n// Reusable: same DSL as ending conditions.\n\nexport interface ComparisonNode {\n  key: string\n  op: string\n  value: unknown\n}\n\nexport interface BooleanNode {\n  all_of?: ConditionNode[]\n  any_of?: ConditionNode[]\n  not?: ConditionNode\n}\n\nexport type ConditionNode = ComparisonNode | BooleanNode | 'default'\n\nfunction isComparison(node: unknown): node is ComparisonNode {\n  return typeof node === 'object' && node !== null && 'key' in node && 'op' in node\n}\n\nfunction isBoolean(node: unknown): node is BooleanNode {\n  return typeof node === 'object' && node !== null && ('all_of' in node || 'any_of' in node || 'not' in node)\n}\n\nexport function evaluateCondition(condition: ConditionNode, state: StateRecord): boolean {\n  if (condition === 'default') return true\n\n  if (isComparison(condition)) {\n    const actual = state[condition.key]\n    const expected = condition.value\n    if (actual === undefined) return false\n\n    switch (condition.op) {\n      case '>=': return typeof actual === 'number' && typeof expected === 'number' && actual >= expected\n      case '<=': return typeof actual === 'number' && typeof expected === 'number' && actual <= expected\n      case '>': return typeof actual === 'number' && typeof expected === 'number' && actual > expected\n      case '<': return typeof actual === 'number' && typeof expected === 'number' && actual < expected\n      case '==': return actual === expected\n      case '!=': return actual !== expected\n      default: return false\n    }\n  }\n\n  if (isBoolean(condition)) {\n    if (condition.all_of) {\n      return condition.all_of.every((c) => evaluateCondition(c as ConditionNode, state))\n    }\n    if (condition.any_of) {\n      return condition.any_of.some((c) => evaluateCondition(c as ConditionNode, state))\n    }\n    if (condition.not) {\n      return !evaluateCondition(condition.not as ConditionNode, state)\n    }\n  }\n\n  return false\n}\n\n// ── Route command ────────────────────────────────────────────────\n\nexport interface RoutingEntry {\n  route_id: string\n  condition: unknown\n  next: string\n}\n\nexport interface RouteResult {\n  ok: true\n  routeId: string\n  nextScene: string\n}\n\nexport interface RouteError {\n  ok: false\n  error: string\n}\n\nexport function runRoute(\n  skillRoot: string,\n  scriptId: string,\n  gateSceneId: string,\n): RouteResult | RouteError {\n  const scriptPath = resolveScriptPath(skillRoot, scriptId)\n  const script = loadScriptFile(scriptPath)\n  const paths = resolveSavePaths(skillRoot, scriptId, 'auto')\n  const meta = readMetaFile(paths.metaYamlPath)\n  const parsedState = readStateFile(paths.stateYamlPath)\n\n  // Get the gate scene from raw script data (scenes may not have 'routing' in ParsedScript)\n  const rawScenes = (script.raw as Record<string, unknown>).scenes as Record<string, unknown> | undefined\n  if (!rawScenes) {\n    return { ok: false, error: 'script has no scenes' }\n  }\n  const gateScene = rawScenes[gateSceneId] as Record<string, unknown> | undefined\n  if (!gateScene) {\n    return { ok: false, error: `gate scene \"${gateSceneId}\" not found` }\n  }\n  if (gateScene.type !== 'affinity_gate') {\n    return { ok: false, error: `scene \"${gateSceneId}\" is not an affinity_gate (type: ${gateScene.type ?? 'undefined'})` }\n  }\n\n  const routing = gateScene.routing as RoutingEntry[] | undefined\n  if (!Array.isArray(routing) || routing.length === 0) {\n    return { ok: false, error: `gate scene \"${gateSceneId}\" has no routing entries` }\n  }\n\n  // Evaluate conditions in order\n  for (const entry of routing) {\n    if (evaluateCondition(entry.condition as ConditionNode, parsedState.state)) {\n      // Write current_route to meta\n      const newMeta: MetaFile = {\n        scriptRef: meta.scriptRef,\n        currentScene: entry.next,\n        lastPlayedAt: new Date().toISOString(),\n        currentRoute: entry.route_id,\n      }\n      atomicWrite(paths.metaYamlPath, serializeMetaFile(newMeta))\n\n      return { ok: true, routeId: entry.route_id, nextScene: entry.next }\n    }\n  }\n\n  // Should not reach here if routing has a default, but just in case\n  return { ok: false, error: 'no routing condition matched (missing default?)' }\n}\n",
  "save.ts": "/**\n * `state save <script-id> [--overwrite <timestamp>]`\n *\n * Creates a manual save by copying the auto/ save to manual/<timestamp>/.\n * Returns MANUAL_SAVE_LIMIT_REACHED if already at 3 manual saves (unless\n * --overwrite is used to replace one).\n */\n\nimport { existsSync, readdirSync, rmSync } from 'node:fs'\nimport { join } from 'node:path'\nimport {\n  resolveSavePaths,\n  readStateFile,\n  readMetaFile,\n  writeSaveTransaction,\n} from './io.js'\nimport { copyHistory, historyPath } from './history.js'\n\nexport const MANUAL_SAVE_LIMIT = 3\n\nexport interface SaveResult {\n  ok: true\n  scriptId: string\n  timestamp: string\n  currentScene: string\n}\n\nexport interface SaveLimitError {\n  ok: false\n  code: 'MANUAL_SAVE_LIMIT_REACHED'\n  scriptId: string\n  existing: string[]\n}\n\nexport interface SaveError {\n  ok: false\n  code: string\n  message: string\n}\n\nexport type SaveOutcome = SaveResult | SaveLimitError | SaveError\n\nexport function runSave(\n  skillRoot: string,\n  scriptId: string,\n  overwrite?: string\n): SaveOutcome {\n  // Read auto save\n  const autoPaths = resolveSavePaths(skillRoot, scriptId, 'auto')\n  if (!existsSync(autoPaths.metaYamlPath) || !existsSync(autoPaths.stateYamlPath)) {\n    return {\n      ok: false,\n      code: 'NO_AUTO_SAVE',\n      message: `no auto save found for script \"${scriptId}\"`,\n    }\n  }\n\n  const autoMeta = readMetaFile(autoPaths.metaYamlPath)\n  const autoState = readStateFile(autoPaths.stateYamlPath)\n\n  // If overwriting, delete the old manual save first\n  if (overwrite !== undefined) {\n    const oldDir = join(skillRoot, 'runtime', 'saves', scriptId, 'manual', overwrite)\n    if (existsSync(oldDir)) {\n      rmSync(oldDir, { recursive: true, force: true })\n    }\n  }\n\n  // Check manual save count\n  const manualDir = join(skillRoot, 'runtime', 'saves', scriptId, 'manual')\n  if (existsSync(manualDir)) {\n    const existing = readdirSync(manualDir, { withFileTypes: true })\n      .filter((e) => e.isDirectory())\n      .map((e) => e.name)\n      .sort()\n\n    if (existing.length >= MANUAL_SAVE_LIMIT) {\n      return {\n        ok: false,\n        code: 'MANUAL_SAVE_LIMIT_REACHED',\n        scriptId,\n        existing,\n      }\n    }\n  }\n\n  // Create new manual save\n  const timestamp = String(Math.floor(Date.now() / 1000))\n  const manualPaths = resolveSavePaths(skillRoot, scriptId, { manual: timestamp })\n\n  writeSaveTransaction(\n    manualPaths,\n    { currentScene: autoState.currentScene, state: { ...autoState.state } },\n    {\n      scriptRef: autoMeta.scriptRef,\n      currentScene: autoMeta.currentScene,\n      lastPlayedAt: new Date().toISOString(),\n    }\n  )\n\n  // Copy history.log to manual save\n  copyHistory(\n    historyPath(autoPaths.stateYamlPath),\n    historyPath(manualPaths.stateYamlPath)\n  )\n\n  return {\n    ok: true,\n    scriptId,\n    timestamp,\n    currentScene: autoMeta.currentScene,\n  }\n}\n",
  "schema.ts": "/**\n * StateSchema: typed representation of the `state_schema` block embedded at\n * the top of every runtime/scripts/script-<id>.yaml. Drives all state writes\n * at skill runtime.\n *\n * This module is the single source of truth for:\n *   - what fields exist in a script\n *   - how to apply a consequences delta to a state field (clamp / overwrite)\n *   - how to materialize initial state from the schema\n *\n * It is intentionally free of filesystem access — the init/apply/validate/\n * rebuild/reset command modules compose it with mini-yaml IO.\n */\n\nimport { parseMiniYaml, type MiniBlock, type MiniPrimitive } from './mini-yaml.js'\n\nexport type StateFieldType = 'int' | 'bool' | 'enum' | 'string'\n\nexport interface IntField {\n  type: 'int'\n  desc: string\n  default: number\n  range: [number, number]\n}\n\nexport interface BoolField {\n  type: 'bool'\n  desc: string\n  default: boolean\n}\n\nexport interface EnumField {\n  type: 'enum'\n  desc: string\n  default: string\n  values: string[]\n}\n\nexport interface StringField {\n  type: 'string'\n  desc: string\n  default: string\n}\n\nexport type StateField = IntField | BoolField | EnumField | StringField\n\nexport type StateSchema = Record<string, StateField>\n\nexport type StateRecord = Record<string, MiniPrimitive>\n\nexport class StateSchemaError extends Error {\n  constructor(message: string) {\n    super(message)\n    this.name = 'StateSchemaError'\n  }\n}\n\n/**\n * Load the state_schema block from a parsed script.yaml document.\n *\n * Expects the script document to have a top-level `state_schema:` mapping\n * where each entry is itself a mapping with `type/desc/default/...` keys.\n * Since mini-yaml only supports one nesting level, the script.yaml is\n * parsed with a more permissive parser upstream (yaml lib). This function\n * accepts an already-parsed plain object.\n */\nexport function loadStateSchema(raw: unknown): StateSchema {\n  if (!isPlainObject(raw)) {\n    throw new StateSchemaError('state_schema must be a mapping')\n  }\n  const schema: StateSchema = {}\n  for (const [key, fieldRaw] of Object.entries(raw)) {\n    schema[key] = parseField(key, fieldRaw)\n  }\n  return schema\n}\n\nfunction parseField(key: string, raw: unknown): StateField {\n  if (!isPlainObject(raw)) {\n    throw new StateSchemaError(`field \"${key}\" must be a mapping`)\n  }\n  const type = raw.type\n  const desc = typeof raw.desc === 'string' ? raw.desc : ''\n  if (type === 'int') {\n    const def = raw.default\n    const range = raw.range\n    if (typeof def !== 'number' || !Number.isInteger(def)) {\n      throw new StateSchemaError(`field \"${key}\": int default must be integer`)\n    }\n    if (!Array.isArray(range) || range.length !== 2) {\n      throw new StateSchemaError(`field \"${key}\": int range must be [min, max]`)\n    }\n    const [min, max] = range\n    if (\n      typeof min !== 'number' ||\n      typeof max !== 'number' ||\n      !Number.isInteger(min) ||\n      !Number.isInteger(max) ||\n      min > max\n    ) {\n      throw new StateSchemaError(`field \"${key}\": invalid int range`)\n    }\n    if (def < min || def > max) {\n      throw new StateSchemaError(`field \"${key}\": default ${def} out of range [${min}, ${max}]`)\n    }\n    return { type: 'int', desc, default: def, range: [min, max] }\n  }\n  if (type === 'bool') {\n    if (typeof raw.default !== 'boolean') {\n      throw new StateSchemaError(`field \"${key}\": bool default must be boolean`)\n    }\n    return { type: 'bool', desc, default: raw.default }\n  }\n  if (type === 'enum') {\n    const values = raw.values\n    if (!Array.isArray(values) || values.some((v) => typeof v !== 'string') || values.length === 0) {\n      throw new StateSchemaError(`field \"${key}\": enum values must be non-empty string array`)\n    }\n    const def = raw.default\n    if (typeof def !== 'string' || !values.includes(def)) {\n      throw new StateSchemaError(`field \"${key}\": enum default \"${String(def)}\" not in values`)\n    }\n    return { type: 'enum', desc, default: def, values: values.slice() as string[] }\n  }\n  if (type === 'string') {\n    if (typeof raw.default !== 'string') {\n      throw new StateSchemaError(`field \"${key}\": string default must be string`)\n    }\n    return { type: 'string', desc, default: raw.default }\n  }\n  throw new StateSchemaError(`field \"${key}\": unknown type \"${String(type)}\"`)\n}\n\n/**\n * Build an initial state record from schema defaults. Output is a flat\n * key→primitive map, ready to be placed into state.yaml's `state:` block.\n */\nexport function buildInitialState(schema: StateSchema): StateRecord {\n  const out: StateRecord = {}\n  for (const [key, field] of Object.entries(schema)) {\n    out[key] = field.default\n  }\n  return out\n}\n\n/**\n * Apply a single consequences delta to a state record. Mutates `state` in\n * place. Returns a ChangeEntry describing the effect for stdout reporting.\n *\n * Semantics:\n *   - int:    new = clamp(old + delta, range)\n *   - bool:   new = delta (overwrite, delta must be boolean)\n *   - enum:   new = delta (overwrite, delta must be in values)\n *   - string: new = delta (overwrite)\n */\nexport interface ChangeEntry {\n  key: string\n  type: StateFieldType\n  oldValue: MiniPrimitive\n  newValue: MiniPrimitive\n  clamped?: boolean\n}\n\nexport function applyDelta(\n  schema: StateSchema,\n  state: StateRecord,\n  key: string,\n  rawDelta: unknown\n): ChangeEntry {\n  const field = schema[key]\n  if (field === undefined) {\n    throw new StateSchemaError(`unknown state key: \"${key}\"`)\n  }\n  const oldValue = state[key]\n  if (oldValue === undefined) {\n    throw new StateSchemaError(`state missing field \"${key}\" (not initialized)`)\n  }\n\n  if (field.type === 'int') {\n    if (typeof rawDelta !== 'number' || !Number.isInteger(rawDelta)) {\n      throw new StateSchemaError(\n        `field \"${key}\" expects int delta, got ${JSON.stringify(rawDelta)}`\n      )\n    }\n    if (typeof oldValue !== 'number') {\n      throw new StateSchemaError(`state[${key}] has wrong type (expected int)`)\n    }\n    const [min, max] = field.range\n    const raw = oldValue + rawDelta\n    const clampedValue = Math.max(min, Math.min(max, raw))\n    state[key] = clampedValue\n    return {\n      key,\n      type: 'int',\n      oldValue,\n      newValue: clampedValue,\n      clamped: raw !== clampedValue,\n    }\n  }\n\n  if (field.type === 'bool') {\n    if (typeof rawDelta !== 'boolean') {\n      throw new StateSchemaError(\n        `field \"${key}\" expects bool, got ${JSON.stringify(rawDelta)}`\n      )\n    }\n    state[key] = rawDelta\n    return { key, type: 'bool', oldValue, newValue: rawDelta }\n  }\n\n  if (field.type === 'enum') {\n    if (typeof rawDelta !== 'string') {\n      throw new StateSchemaError(\n        `field \"${key}\" expects enum string, got ${JSON.stringify(rawDelta)}`\n      )\n    }\n    if (!field.values.includes(rawDelta)) {\n      throw new StateSchemaError(\n        `field \"${key}\": value \"${rawDelta}\" not in [${field.values.join(', ')}]`\n      )\n    }\n    state[key] = rawDelta\n    return { key, type: 'enum', oldValue, newValue: rawDelta }\n  }\n\n  // string\n  if (typeof rawDelta !== 'string') {\n    throw new StateSchemaError(\n      `field \"${key}\" expects string, got ${JSON.stringify(rawDelta)}`\n    )\n  }\n  state[key] = rawDelta\n  return { key, type: 'string', oldValue, newValue: rawDelta }\n}\n\n/**\n * Check if the value in a state record matches the schema type. Used by\n * validate.ts to flag type drift.\n */\nexport function validateFieldType(\n  field: StateField,\n  value: MiniPrimitive\n): boolean {\n  if (field.type === 'int') {\n    return typeof value === 'number' && Number.isInteger(value)\n  }\n  if (field.type === 'bool') {\n    return typeof value === 'boolean'\n  }\n  if (field.type === 'enum') {\n    return typeof value === 'string' && field.values.includes(value)\n  }\n  return typeof value === 'string'\n}\n\n/**\n * Parse a state.yaml file content into { current_scene, state } using\n * mini-yaml. Throws if the shape is unexpected.\n */\nexport interface ParsedStateFile {\n  currentScene: string\n  state: StateRecord\n}\n\nexport function parseStateFile(text: string): ParsedStateFile {\n  const doc = parseMiniYaml(text)\n  const currentScene = doc.current_scene\n  const stateBlock = doc.state\n  if (typeof currentScene !== 'string') {\n    throw new StateSchemaError('state.yaml missing top-level current_scene')\n  }\n  if (!isMiniBlock(stateBlock)) {\n    throw new StateSchemaError('state.yaml missing top-level state: block')\n  }\n  return { currentScene, state: { ...stateBlock } }\n}\n\nfunction isMiniBlock(v: unknown): v is MiniBlock {\n  return typeof v === 'object' && v !== null && !Array.isArray(v)\n}\n\nfunction isPlainObject(v: unknown): v is Record<string, unknown> {\n  return typeof v === 'object' && v !== null && !Array.isArray(v)\n}\n",
  "script-builder.ts": "/**\n * Incremental script builder — plan / scene / ending / build.\n *\n * Phase 1 LLM generates script in steps:\n * 1. Plan: narrative blueprint (schema, outlines, scene graph)\n * 2. Scenes: one at a time, in topological order\n * 3. Endings: after all scenes, based on actual scene content\n * 4. Build: merge into final script-<id>.json\n */\n\nimport {\n  readFileSync,\n  writeFileSync,\n  existsSync,\n  mkdirSync,\n  readdirSync,\n  renameSync,\n  unlinkSync,\n  rmSync,\n} from 'node:fs'\nimport { join, dirname } from 'node:path'\nimport { loadStateSchema, type StateSchema } from './schema.js'\nimport type { MiniPrimitive } from './mini-yaml.js'\n\n// ── Plan types ───────────────────────────────────────────────────\n\nexport interface PlanChoice {\n  id: string\n  text: string\n  intent: string\n  next: string\n}\n\nexport interface PlanRoutingEntry {\n  route_id: string\n  condition: unknown\n  next: string\n}\n\nexport interface PlanScene {\n  act: number\n  title: string\n  cast?: string[]\n  outline: string\n  emotional_beat?: string\n  state_changes_intent?: Record<string, MiniPrimitive>\n  choices: PlanChoice[]\n  continuity?: string\n  context_refs?: string[]\n  // Route support:\n  type?: 'affinity_gate'\n  routing?: PlanRoutingEntry[]\n  route?: string\n  // Auto-computed by CLI:\n  predecessors?: string[]\n  is_convergence?: boolean\n}\n\nexport interface PlanRoute {\n  id: string\n  focus_character: string\n  name: string\n  theme: string\n  scenes: string[]\n}\n\nexport interface PlanEnding {\n  id: string\n  title: string\n  condition: unknown\n  intent: string\n  route?: string\n}\n\nexport interface PlanNarrative {\n  arc: string\n  acts: Array<{ act: number; title: string; theme: string; scenes: string[] }>\n  character_arcs?: Record<string, { arc: string; key_scenes: string[] }>\n}\n\nexport interface ScriptPlan {\n  id: string\n  state_schema: Record<string, unknown>\n  initial_state: Record<string, MiniPrimitive>\n  narrative: PlanNarrative\n  routes?: PlanRoute[]\n  scenes: Record<string, PlanScene>\n  endings: PlanEnding[]\n  generation_order?: string[]\n}\n\n// ── Scene / ending draft types ───────────────────────────────────\n\nexport interface SceneDraft {\n  text: string\n  choices: Array<{\n    id: string\n    text: string\n    consequences: Record<string, MiniPrimitive>\n    next: string\n  }>\n  route?: string\n}\n\nexport interface EndingDraft {\n  id: string\n  title: string\n  condition: unknown\n  body: string\n}\n\n// ── Build paths ──────────────────────────────────────────────────\n\nfunction buildDir(skillRoot: string, scriptId: string): string {\n  return join(skillRoot, 'runtime', 'scripts', `.build-${scriptId}`)\n}\n\nfunction planPath(skillRoot: string, scriptId: string): string {\n  return join(buildDir(skillRoot, scriptId), 'plan.json')\n}\n\nfunction draftPath(skillRoot: string, scriptId: string, name: string): string {\n  return join(buildDir(skillRoot, scriptId), 'draft', `${name}.json`)\n}\n\nfunction scenePath(skillRoot: string, scriptId: string, sceneId: string): string {\n  return join(buildDir(skillRoot, scriptId), 'scenes', `${sceneId}.json`)\n}\n\nfunction endingPath(skillRoot: string, scriptId: string, endingId: string): string {\n  return join(buildDir(skillRoot, scriptId), 'endings', `${endingId}.json`)\n}\n\n// ── runScriptPlan ────────────────────────────────────────────────\n\nexport interface PlanResult {\n  ok: true\n  scenes: number\n  fields: number\n  acts: number\n  endings: number\n  generationOrder: string[]\n  convergencePoints: string[]\n}\n\nexport interface PlanError {\n  ok: false\n  error: string\n}\n\nexport function runScriptPlan(skillRoot: string, scriptId: string): PlanResult | PlanError {\n  const path = planPath(skillRoot, scriptId)\n  if (!existsSync(path)) {\n    return { ok: false, error: `plan.json not found at ${path}` }\n  }\n\n  let plan: ScriptPlan\n  try {\n    plan = JSON.parse(readFileSync(path, 'utf8'))\n  } catch (err) {\n    return { ok: false, error: `plan.json is not valid JSON: ${(err as Error).message}` }\n  }\n\n  // Validate state_schema\n  try {\n    loadStateSchema(plan.state_schema)\n  } catch (err) {\n    return { ok: false, error: `state_schema invalid: ${(err as Error).message}` }\n  }\n\n  // Validate initial_state == schema keys\n  const schemaKeys = new Set(Object.keys(plan.state_schema))\n  const initKeys = new Set(Object.keys(plan.initial_state))\n  for (const k of schemaKeys) {\n    if (!initKeys.has(k)) return { ok: false, error: `initial_state missing field \"${k}\"` }\n  }\n  for (const k of initKeys) {\n    if (!schemaKeys.has(k)) return { ok: false, error: `initial_state has extra field \"${k}\"` }\n  }\n\n  const sceneIds = new Set(Object.keys(plan.scenes))\n  if (sceneIds.size === 0) {\n    return { ok: false, error: 'plan.scenes must not be empty' }\n  }\n\n  // Validate each scene\n  for (const [sid, scene] of Object.entries(plan.scenes)) {\n    if (!scene.outline || scene.outline.trim() === '') {\n      return { ok: false, error: `scene \"${sid}\" missing outline` }\n    }\n\n    // Gate scenes have routing instead of choices\n    if (scene.type === 'affinity_gate') {\n      if (!Array.isArray(scene.routing) || scene.routing.length === 0) {\n        return { ok: false, error: `gate scene \"${sid}\" missing routing array` }\n      }\n      const lastRouting = scene.routing[scene.routing.length - 1]!\n      if (lastRouting.condition !== 'default') {\n        return { ok: false, error: `gate scene \"${sid}\" routing last entry must be condition: \"default\"` }\n      }\n      for (const r of scene.routing) {\n        if (!r.route_id) {\n          return { ok: false, error: `gate scene \"${sid}\" routing entry missing route_id` }\n        }\n        if (r.next && !sceneIds.has(r.next)) {\n          return { ok: false, error: `gate scene \"${sid}\" routing next \"${r.next}\" does not exist` }\n        }\n      }\n    } else {\n      // Normal scene\n      if (!Array.isArray(scene.choices)) {\n        return { ok: false, error: `scene \"${sid}\" missing choices array` }\n      }\n      if (scene.choices.length > 3) {\n        return { ok: false, error: `scene \"${sid}\" has ${scene.choices.length} choices (max 3)` }\n      }\n      for (const c of scene.choices) {\n        if (c.next && !sceneIds.has(c.next)) {\n          return { ok: false, error: `scene \"${sid}\" choice \"${c.id}\" next \"${c.next}\" does not exist` }\n        }\n      }\n    }\n\n    if (scene.context_refs) {\n      for (const ref of scene.context_refs) {\n        if (!sceneIds.has(ref)) {\n          return { ok: false, error: `scene \"${sid}\" context_ref \"${ref}\" does not exist` }\n        }\n      }\n    }\n  }\n\n  // Validate routes (if present)\n  if (plan.routes && plan.routes.length > 0) {\n    const routeIds = new Set(plan.routes.map((r) => r.id))\n    // Each route's scenes must exist\n    for (const route of plan.routes) {\n      for (const sid of route.scenes) {\n        if (!sceneIds.has(sid)) {\n          return { ok: false, error: `route \"${route.id}\" references non-existent scene \"${sid}\"` }\n        }\n      }\n    }\n    // Each route must have at least 1 ending\n    for (const route of plan.routes) {\n      const routeEndings = plan.endings.filter((e) => e.route === route.id)\n      if (routeEndings.length === 0) {\n        return { ok: false, error: `route \"${route.id}\" has no endings` }\n      }\n    }\n    // Route scene count balance warning (not blocking)\n    const routeSceneCounts = plan.routes.map((r) => r.scenes.length)\n    const maxCount = Math.max(...routeSceneCounts)\n    const minCount = Math.min(...routeSceneCounts)\n    if (maxCount - minCount > 2) {\n      // Warning only, don't block — logged to stderr by caller if needed\n    }\n  }\n\n  // Validate endings\n  if (!Array.isArray(plan.endings) || plan.endings.length === 0) {\n    return { ok: false, error: 'plan.endings must be a non-empty array' }\n  }\n  for (const ending of plan.endings) {\n    if (!ending.id || !ending.title) {\n      return { ok: false, error: 'each ending must have id and title' }\n    }\n    if (!ending.intent || ending.intent.trim() === '') {\n      return { ok: false, error: `ending \"${ending.id}\" missing intent` }\n    }\n  }\n\n  // Auto-compute predecessors + is_convergence\n  const predecessorsMap = new Map<string, string[]>()\n  for (const sid of sceneIds) predecessorsMap.set(sid, [])\n\n  for (const [sid, scene] of Object.entries(plan.scenes)) {\n    if (scene.type === 'affinity_gate' && scene.routing) {\n      for (const r of scene.routing) {\n        if (r.next && sceneIds.has(r.next)) {\n          predecessorsMap.get(r.next)!.push(sid)\n        }\n      }\n    } else if (scene.choices) {\n      for (const c of scene.choices) {\n        if (c.next && sceneIds.has(c.next)) {\n          predecessorsMap.get(c.next)!.push(sid)\n        }\n      }\n    }\n  }\n\n  for (const [sid, preds] of predecessorsMap) {\n    plan.scenes[sid]!.predecessors = preds\n    plan.scenes[sid]!.is_convergence = preds.length > 1\n  }\n\n  // Topological sort + cycle detection\n  const topoResult = topologicalSort(plan.scenes)\n  if (!topoResult.ok) {\n    return { ok: false, error: topoResult.error }\n  }\n  plan.generation_order = topoResult.order\n\n  // Write enriched plan back\n  writeFileSync(path, JSON.stringify(plan, null, 2), 'utf8')\n\n  // Ensure subdirectories exist\n  const bd = buildDir(skillRoot, scriptId)\n  mkdirSync(join(bd, 'draft'), { recursive: true })\n  mkdirSync(join(bd, 'scenes'), { recursive: true })\n  mkdirSync(join(bd, 'endings'), { recursive: true })\n\n  const convergencePoints = Object.entries(plan.scenes)\n    .filter(([, s]) => s.is_convergence)\n    .map(([id]) => id)\n\n  return {\n    ok: true,\n    scenes: sceneIds.size,\n    fields: schemaKeys.size,\n    acts: plan.narrative?.acts?.length ?? 0,\n    endings: plan.endings.length,\n    generationOrder: topoResult.order,\n    convergencePoints,\n  }\n}\n\n// ── Topological sort ─────────────────────────────────────────────\n\ninterface TopoOk { ok: true; order: string[] }\ninterface TopoError { ok: false; error: string }\n\nexport function topologicalSort(scenes: Record<string, PlanScene>): TopoOk | TopoError {\n  const ids = Object.keys(scenes)\n  if (ids.length === 0) return { ok: true, order: [] }\n\n  // Build adjacency: scene → set of scenes it points to via choices\n  const outEdges = new Map<string, string[]>()\n  const inDegree = new Map<string, number>()\n\n  for (const id of ids) {\n    outEdges.set(id, [])\n    inDegree.set(id, 0)\n  }\n\n  for (const [sid, scene] of Object.entries(scenes)) {\n    // Gate scenes use routing instead of choices\n    if (scene.type === 'affinity_gate' && scene.routing) {\n      for (const r of scene.routing) {\n        if (r.next && scenes[r.next]) {\n          outEdges.get(sid)!.push(r.next)\n          inDegree.set(r.next, (inDegree.get(r.next) ?? 0) + 1)\n        }\n      }\n    } else if (scene.choices) {\n      for (const c of scene.choices) {\n        if (c.next && scenes[c.next]) {\n          outEdges.get(sid)!.push(c.next)\n          inDegree.set(c.next, (inDegree.get(c.next) ?? 0) + 1)\n        }\n      }\n    }\n  }\n\n  // Kahn's algorithm\n  const queue: string[] = []\n  for (const [id, deg] of inDegree) {\n    if (deg === 0) queue.push(id)\n  }\n\n  const order: string[] = []\n  while (queue.length > 0) {\n    const node = queue.shift()!\n    order.push(node)\n    for (const next of outEdges.get(node)!) {\n      const newDeg = inDegree.get(next)! - 1\n      inDegree.set(next, newDeg)\n      if (newDeg === 0) queue.push(next)\n    }\n  }\n\n  if (order.length !== ids.length) {\n    const remaining = ids.filter(id => !order.includes(id))\n    return { ok: false, error: `cycle detected involving: ${remaining.join(', ')}` }\n  }\n\n  return { ok: true, order }\n}\n\n// ── runScriptScene ───────────────────────────────────────────────\n\nexport interface SceneResult {\n  ok: true\n  sceneId: string\n  choices: number\n  consequenceKeys: number\n}\n\nexport interface SceneError {\n  ok: false\n  error: string\n}\n\nexport function runScriptScene(\n  skillRoot: string,\n  scriptId: string,\n  sceneId: string,\n): SceneResult | SceneError {\n  // Read plan\n  const pPath = planPath(skillRoot, scriptId)\n  if (!existsSync(pPath)) return { ok: false, error: 'plan.json not found — run script plan first' }\n  let plan: ScriptPlan\n  try {\n    plan = JSON.parse(readFileSync(pPath, 'utf8'))\n  } catch { return { ok: false, error: 'plan.json is not valid JSON' } }\n\n  // Check scene-id exists in plan\n  const planScene = plan.scenes[sceneId]\n  if (!planScene) {\n    return { ok: false, error: `scene \"${sceneId}\" not found in plan.scenes` }\n  }\n\n  // Gate scenes: validate JSON,补全 type/routing/choices from plan, then write\n  if (planScene.type === 'affinity_gate') {\n    const dp = draftPath(skillRoot, scriptId, sceneId)\n    if (!existsSync(dp)) {\n      return { ok: false, error: `draft/${sceneId}.json not found` }\n    }\n    let draft: Record<string, unknown>\n    try {\n      draft = JSON.parse(readFileSync(dp, 'utf8'))\n    } catch (err) {\n      return { ok: false, error: `draft/${sceneId}.json JSON error: ${(err as Error).message}` }\n    }\n    // Check predecessors ready\n    if (planScene.predecessors) {\n      for (const pred of planScene.predecessors) {\n        if (!existsSync(scenePath(skillRoot, scriptId, pred))) {\n          return { ok: false, error: `gate \"${sceneId}\" predecessor \"${pred}\" not yet generated` }\n        }\n      }\n    }\n    //补全结构字段 from plan (single source of truth)\n    draft.type = 'affinity_gate'\n    draft.choices = draft.choices ?? []\n    if (planScene.routing) {\n      draft.routing = planScene.routing\n    }\n    const dest = scenePath(skillRoot, scriptId, sceneId)\n    mkdirSync(dirname(dest), { recursive: true })\n    writeFileSync(dest, JSON.stringify(draft, null, 2), 'utf8')\n    // Clean up draft\n    try { unlinkSync(dp) } catch { /* ignore */ }\n    return { ok: true, sceneId, choices: 0, consequenceKeys: 0 }\n  }\n\n  // Read draft\n  const dp = draftPath(skillRoot, scriptId, sceneId)\n  if (!existsSync(dp)) {\n    return { ok: false, error: `draft/${sceneId}.json not found` }\n  }\n  let draft: SceneDraft\n  try {\n    draft = JSON.parse(readFileSync(dp, 'utf8'))\n  } catch (err) {\n    return { ok: false, error: `draft/${sceneId}.json JSON error: ${(err as Error).message}` }\n  }\n\n  // Validate text\n  if (!draft.text || draft.text.trim() === '') {\n    return { ok: false, error: `scene \"${sceneId}\" text is empty` }\n  }\n\n  // Validate choices match plan\n  if (!Array.isArray(draft.choices)) {\n    return { ok: false, error: `scene \"${sceneId}\" choices must be an array` }\n  }\n  if (draft.choices.length !== planScene.choices.length) {\n    return {\n      ok: false,\n      error: `scene \"${sceneId}\" has ${draft.choices.length} choices but plan expects ${planScene.choices.length}`,\n    }\n  }\n  for (let i = 0; i < draft.choices.length; i++) {\n    const dc = draft.choices[i]!\n    const pc = planScene.choices[i]!\n    if (dc.id !== pc.id) {\n      return { ok: false, error: `scene \"${sceneId}\" choice[${i}].id \"${dc.id}\" != plan \"${pc.id}\"` }\n    }\n    if (dc.next !== pc.next) {\n      return { ok: false, error: `scene \"${sceneId}\" choice[${i}].next \"${dc.next}\" != plan \"${pc.next}\"` }\n    }\n  }\n\n  // Validate consequences keys ⊂ schema\n  const schema = loadStateSchema(plan.state_schema)\n  let totalKeys = 0\n  for (const choice of draft.choices) {\n    if (!choice.consequences) continue\n    for (const key of Object.keys(choice.consequences)) {\n      if (!(key in schema)) {\n        return { ok: false, error: `scene \"${sceneId}\" consequence key \"${key}\" not in state_schema` }\n      }\n      totalKeys++\n    }\n  }\n\n  // Check predecessors are ready (topological order enforcement)\n  if (planScene.predecessors) {\n    for (const pred of planScene.predecessors) {\n      const sp = scenePath(skillRoot, scriptId, pred)\n      if (!existsSync(sp)) {\n        return {\n          ok: false,\n          error: `scene \"${sceneId}\" predecessor \"${pred}\" not yet generated (topological order violation)`,\n        }\n      }\n    }\n  }\n\n  // Inject route label from plan.routes if applicable\n  if (plan.routes && plan.routes.length > 0) {\n    for (const route of plan.routes) {\n      if (route.scenes.includes(sceneId)) {\n        draft.route = route.id\n        break\n      }\n    }\n  }\n\n  // Write scene (with possible route injection) to scenes/\n  const dest = scenePath(skillRoot, scriptId, sceneId)\n  mkdirSync(dirname(dest), { recursive: true })\n  writeFileSync(dest, JSON.stringify(draft, null, 2), 'utf8')\n  try { unlinkSync(dp) } catch { /* ignore */ }\n\n  return { ok: true, sceneId, choices: draft.choices.length, consequenceKeys: totalKeys }\n}\n\n// ── runScriptEnding ──────────────────────────────────────────────\n\nexport interface EndingResult {\n  ok: true\n  endingId: string\n}\n\nexport interface EndingError {\n  ok: false\n  error: string\n}\n\nexport function runScriptEnding(\n  skillRoot: string,\n  scriptId: string,\n  endingId: string,\n): EndingResult | EndingError {\n  const pPath = planPath(skillRoot, scriptId)\n  if (!existsSync(pPath)) return { ok: false, error: 'plan.json not found' }\n  let plan: ScriptPlan\n  try { plan = JSON.parse(readFileSync(pPath, 'utf8')) }\n  catch { return { ok: false, error: 'plan.json is not valid JSON' } }\n\n  // Check ending exists in plan\n  const planEnding = plan.endings.find(e => e.id === endingId)\n  if (!planEnding) {\n    return { ok: false, error: `ending \"${endingId}\" not found in plan.endings` }\n  }\n\n  // Read draft\n  const dp = draftPath(skillRoot, scriptId, endingId)\n  if (!existsSync(dp)) {\n    return { ok: false, error: `draft/${endingId}.json not found` }\n  }\n  let draft: EndingDraft\n  try { draft = JSON.parse(readFileSync(dp, 'utf8')) }\n  catch (err) {\n    return { ok: false, error: `draft/${endingId}.json JSON error: ${(err as Error).message}` }\n  }\n\n  if (!draft.body || draft.body.trim() === '') {\n    return { ok: false, error: `ending \"${endingId}\" body is empty` }\n  }\n\n  // Move to endings/\n  const dest = endingPath(skillRoot, scriptId, endingId)\n  mkdirSync(dirname(dest), { recursive: true })\n  renameSync(dp, dest)\n\n  return { ok: true, endingId }\n}\n\n// ── runScriptBuild ───────────────────────────────────────────────\n\nexport interface BuildResult {\n  ok: true\n  scriptId: string\n  scenes: number\n  endings: number\n  sizeBytes: number\n}\n\nexport interface BuildError {\n  ok: false\n  error: string\n}\n\nexport function runScriptBuild(skillRoot: string, scriptId: string): BuildResult | BuildError {\n  const pPath = planPath(skillRoot, scriptId)\n  if (!existsSync(pPath)) return { ok: false, error: 'plan.json not found' }\n  let plan: ScriptPlan\n  try { plan = JSON.parse(readFileSync(pPath, 'utf8')) }\n  catch { return { ok: false, error: 'plan.json is not valid JSON' } }\n\n  // Check all scenes exist\n  const missingSc: string[] = []\n  for (const sid of Object.keys(plan.scenes)) {\n    if (!existsSync(scenePath(skillRoot, scriptId, sid))) missingSc.push(sid)\n  }\n  if (missingSc.length > 0) {\n    return { ok: false, error: `missing scenes: ${missingSc.join(', ')}` }\n  }\n\n  // Check all endings exist\n  const missingEnd: string[] = []\n  for (const ending of plan.endings) {\n    if (!existsSync(endingPath(skillRoot, scriptId, ending.id))) missingEnd.push(ending.id)\n  }\n  if (missingEnd.length > 0) {\n    return { ok: false, error: `missing endings: ${missingEnd.join(', ')}` }\n  }\n\n  // Assemble final script (same format as current script.json)\n  const scenes: Record<string, unknown> = {}\n  for (const sid of Object.keys(plan.scenes)) {\n    const sceneData = JSON.parse(readFileSync(scenePath(skillRoot, scriptId, sid), 'utf8'))\n    scenes[sid] = sceneData\n  }\n\n  const endings: unknown[] = []\n  for (const pe of plan.endings) {\n    const endingData = JSON.parse(readFileSync(endingPath(skillRoot, scriptId, pe.id), 'utf8'))\n    endings.push(endingData)\n  }\n\n  const finalScript = {\n    id: plan.id,\n    state_schema: plan.state_schema,\n    initial_state: plan.initial_state,\n    scenes,\n    endings,\n  }\n\n  const json = JSON.stringify(finalScript, null, 2)\n  const outPath = join(skillRoot, 'runtime', 'scripts', `script-${scriptId}.json`)\n  mkdirSync(dirname(outPath), { recursive: true })\n  writeFileSync(outPath, json, 'utf8')\n\n  // Cleanup build dir\n  const bd = buildDir(skillRoot, scriptId)\n  rmSync(bd, { recursive: true, force: true })\n\n  return { ok: true, scriptId, scenes: Object.keys(scenes).length, endings: endings.length, sizeBytes: json.length }\n}\n",
  "script.ts": "/**\n * Script file loader.\n *\n * script-<id>.json is authored by the Phase 1 LLM. Structure (selected parts):\n *\n * {\n *   \"id\": \"script-001\",\n *   \"state_schema\": { \"<key>\": { type, desc, default, range?, values? }, ... },\n *   \"initial_state\": { \"<key>\": <value>, ... },\n *   \"scenes\": {\n *     \"<scene-id>\": {\n *       \"text\": \"...\",\n *       \"choices\": [\n *         { \"id\": \"<choice-id>\", \"text\": \"...\", \"consequences\": { ... }, \"next\": \"<scene-id>\" }\n *       ]\n *     }\n *   },\n *   \"endings\": [...]\n * }\n *\n * This module is the single reader of script files. All state command modules\n * go through it so parsing/validation lives in one place.\n */\n\nimport { readFileSync } from 'node:fs'\nimport { loadStateSchema, type StateSchema, type StateRecord } from './schema.js'\nimport type { MiniPrimitive } from './mini-yaml.js'\n\nexport interface ScriptChoice {\n  id: string\n  text: string\n  consequences: Record<string, MiniPrimitive>\n  next?: string\n}\n\nexport interface ScriptRouting {\n  route_id: string\n  condition: unknown\n  next: string\n}\n\nexport interface ScriptScene {\n  id: string\n  text: string\n  choices: ScriptChoice[]\n  type?: string\n  routing?: ScriptRouting[]\n  route?: string\n}\n\nexport interface ParsedScript {\n  id: string\n  schema: StateSchema\n  initialState: StateRecord\n  scenes: Map<string, ScriptScene>\n  firstSceneId: string\n  raw: Record<string, unknown>\n}\n\nexport class ScriptLoadError extends Error {\n  constructor(message: string) {\n    super(message)\n    this.name = 'ScriptLoadError'\n  }\n}\n\nexport function parseScript(text: string): ParsedScript {\n  let json: unknown\n  try {\n    json = JSON.parse(text)\n  } catch (err) {\n    throw new ScriptLoadError(\n      `script is not valid JSON: ${(err as Error).message}`\n    )\n  }\n  if (!isPlainObject(json)) {\n    throw new ScriptLoadError('script root must be a JSON object')\n  }\n\n  const rawId = json.id\n  if (typeof rawId !== 'string' || rawId === '') {\n    throw new ScriptLoadError('script.id must be a non-empty string')\n  }\n\n  if (!('state_schema' in json)) {\n    throw new ScriptLoadError('script.state_schema is required')\n  }\n  const schema = loadStateSchema(json.state_schema)\n\n  const initialRaw = json.initial_state\n  if (!isPlainObject(initialRaw)) {\n    throw new ScriptLoadError('script.initial_state must be an object')\n  }\n  const initialState: StateRecord = {}\n  for (const [k, v] of Object.entries(initialRaw)) {\n    if (typeof v === 'number' || typeof v === 'boolean' || typeof v === 'string') {\n      initialState[k] = v\n    } else {\n      throw new ScriptLoadError(\n        `initial_state[\"${k}\"] must be int/bool/string, got ${typeof v}`\n      )\n    }\n  }\n\n  const scenesRaw = json.scenes\n  if (!isPlainObject(scenesRaw)) {\n    throw new ScriptLoadError('script.scenes must be an object')\n  }\n  const scenes = new Map<string, ScriptScene>()\n  const sceneIds = Object.keys(scenesRaw)\n  if (sceneIds.length === 0) {\n    throw new ScriptLoadError('script.scenes must not be empty')\n  }\n  for (const [sceneId, sceneRaw] of Object.entries(scenesRaw)) {\n    scenes.set(sceneId, parseScene(sceneId, sceneRaw))\n  }\n\n  return {\n    id: rawId,\n    schema,\n    initialState,\n    scenes,\n    firstSceneId: sceneIds[0]!,\n    raw: json,\n  }\n}\n\nfunction parseScene(sceneId: string, raw: unknown): ScriptScene {\n  if (!isPlainObject(raw)) {\n    throw new ScriptLoadError(`scene \"${sceneId}\" must be an object`)\n  }\n  const text = typeof raw.text === 'string' ? raw.text : ''\n  const sceneType = typeof raw.type === 'string' ? raw.type : undefined\n  const route = typeof raw.route === 'string' ? raw.route : undefined\n\n  // Gate scenes: choices defaults to [], parse routing\n  if (sceneType === 'affinity_gate') {\n    const choicesRaw = raw.choices\n    const choices: ScriptChoice[] = Array.isArray(choicesRaw)\n      ? choicesRaw.map((c, idx) => parseChoice(sceneId, idx, c))\n      : []\n    const routing = Array.isArray(raw.routing)\n      ? (raw.routing as ScriptRouting[])\n      : undefined\n    return { id: sceneId, text, choices, type: sceneType, routing, route }\n  }\n\n  // Normal scenes: choices required\n  const choicesRaw = raw.choices\n  if (!Array.isArray(choicesRaw)) {\n    throw new ScriptLoadError(`scene \"${sceneId}\".choices must be an array`)\n  }\n  const choices: ScriptChoice[] = choicesRaw.map((c, idx) => parseChoice(sceneId, idx, c))\n  return { id: sceneId, text, choices, ...(sceneType ? { type: sceneType } : {}), ...(route ? { route } : {}) }\n}\n\nfunction parseChoice(sceneId: string, idx: number, raw: unknown): ScriptChoice {\n  if (!isPlainObject(raw)) {\n    throw new ScriptLoadError(\n      `scene \"${sceneId}\".choices[${idx}] must be an object`\n    )\n  }\n  const id = typeof raw.id === 'string' ? raw.id : `choice-${idx}`\n  const text = typeof raw.text === 'string' ? raw.text : ''\n  const consequencesRaw = raw.consequences ?? {}\n  if (!isPlainObject(consequencesRaw)) {\n    throw new ScriptLoadError(\n      `scene \"${sceneId}\".choices[${idx}].consequences must be an object`\n    )\n  }\n  const consequences: Record<string, MiniPrimitive> = {}\n  for (const [k, v] of Object.entries(consequencesRaw)) {\n    if (typeof v === 'number' || typeof v === 'boolean' || typeof v === 'string') {\n      consequences[k] = v\n    } else {\n      throw new ScriptLoadError(\n        `scene \"${sceneId}\".choices[${idx}].consequences[\"${k}\"] must be int/bool/string`\n      )\n    }\n  }\n  const next = typeof raw.next === 'string' ? raw.next : undefined\n  return { id, text, consequences, next }\n}\n\nexport function loadScriptFile(path: string): ParsedScript {\n  let text: string\n  try {\n    text = readFileSync(path, 'utf8')\n  } catch (err) {\n    throw new ScriptLoadError(`cannot read script file: ${path}`)\n  }\n  return parseScript(text)\n}\n\nfunction isPlainObject(v: unknown): v is Record<string, unknown> {\n  return typeof v === 'object' && v !== null && !Array.isArray(v)\n}\n",
  "scripts.ts": "/**\n * `state scripts` — list all generated scripts in this skill archive.\n *\n * Scans runtime/scripts/ for script-*.json files and extracts top-level\n * metadata fields (id, title, generated_at) without loading full scene data.\n */\n\nimport { readdirSync, readFileSync } from 'node:fs'\nimport { join } from 'node:path'\n\nexport interface ScriptEntry {\n  id: string\n  title: string\n  generated_at: string\n  file: string\n  error?: string\n}\n\nexport interface ScriptsResult {\n  scripts: ScriptEntry[]\n  count: number\n}\n\nexport function runScripts(skillRoot: string): ScriptsResult {\n  const scriptsDir = join(skillRoot, 'runtime', 'scripts')\n\n  let files: string[]\n  try {\n    files = readdirSync(scriptsDir)\n  } catch {\n    // Directory doesn't exist — no scripts\n    return { scripts: [], count: 0 }\n  }\n\n  const scriptFiles = files.filter(\n    (f) => f.startsWith('script-') && f.endsWith('.json')\n  )\n\n  const scripts: ScriptEntry[] = []\n\n  for (const file of scriptFiles) {\n    const filePath = join(scriptsDir, file)\n    try {\n      const raw = JSON.parse(readFileSync(filePath, 'utf8'))\n      scripts.push({\n        id: raw.id ?? file.replace(/^script-|\\.json$/g, ''),\n        title: raw.title ?? '',\n        generated_at: raw.generated_at ?? '',\n        file,\n      })\n    } catch (err) {\n      scripts.push({\n        id: file.replace(/^script-|\\.json$/g, ''),\n        title: '',\n        generated_at: '',\n        file,\n        error: (err as Error).message,\n      })\n    }\n  }\n\n  return { scripts, count: scripts.length }\n}\n",
  "tree.ts": "/**\n * `state tree <script-id>` / `state tree --stop`\n *\n * Manages the branch tree visualization server lifecycle:\n * - Start: spawn detached tree-server process, write server.json\n * - Reuse: if server already running, reuse (switch script if needed)\n * - Stop: kill server process, clean server.json\n */\n\nimport { existsSync, readFileSync, unlinkSync, mkdirSync } from 'node:fs'\nimport { join, dirname } from 'node:path'\nimport { spawn, execSync } from 'node:child_process'\n\ninterface ServerInfo {\n  port: number\n  pid: number\n  scriptId: string\n}\n\nfunction serverJsonPath(skillRoot: string): string {\n  return join(skillRoot, 'runtime', 'tree', 'server.json')\n}\n\nfunction readServerInfo(skillRoot: string): ServerInfo | null {\n  const path = serverJsonPath(skillRoot)\n  if (!existsSync(path)) return null\n  try {\n    return JSON.parse(readFileSync(path, 'utf8'))\n  } catch {\n    return null\n  }\n}\n\nfunction isProcessAlive(pid: number): boolean {\n  try {\n    process.kill(pid, 0)\n    return true\n  } catch {\n    return false\n  }\n}\n\nexport interface TreeResult {\n  action: 'started' | 'reused' | 'switched'\n  url: string\n  port: number\n  pid: number\n}\n\nexport interface TreeStopResult {\n  action: 'stopped' | 'not_running'\n}\n\nexport async function runTree(skillRoot: string, scriptId: string): Promise<TreeResult> {\n  const info = readServerInfo(skillRoot)\n\n  // Reuse existing server\n  if (info && isProcessAlive(info.pid)) {\n    if (info.scriptId === scriptId) {\n      return { action: 'reused', url: `http://localhost:${info.port}`, port: info.port, pid: info.pid }\n    }\n    // Switch script\n    try {\n      const res = await fetch(`http://localhost:${info.port}/switch`, {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({ scriptId }),\n      })\n      if (res.ok) {\n        return { action: 'switched', url: `http://localhost:${info.port}`, port: info.port, pid: info.pid }\n      }\n    } catch {\n      // Server not responding, clean up and restart\n    }\n    // Clean stale server.json\n    try { unlinkSync(serverJsonPath(skillRoot)) } catch { /* ignore */ }\n  } else if (info) {\n    // PID dead, clean up\n    try { unlinkSync(serverJsonPath(skillRoot)) } catch { /* ignore */ }\n  }\n\n  // Start new server\n  const treeDir = join(skillRoot, 'runtime', 'tree')\n  if (!existsSync(treeDir)) mkdirSync(treeDir, { recursive: true })\n\n  // Use viewer-server via main.ts 'viewer' subcommand path\n  // Spawns soulkiller runtime viewer tree <script-id> as a detached process\n  const mainScript = join(dirname(new URL(import.meta.url).pathname), 'main.ts')\n\n  return new Promise<TreeResult>((resolve, reject) => {\n    const child = spawn(process.execPath, [mainScript, 'viewer', 'tree', scriptId], {\n      env: { ...process.env, BUN_BE_BUN: '1', SKILL_ROOT: skillRoot },\n      stdio: ['ignore', 'pipe', 'ignore'],\n      detached: true,\n    })\n\n    let output = ''\n    child.stdout!.on('data', (chunk: Buffer) => {\n      output += chunk.toString()\n      const match = output.match(/VIEWER_URL (http:\\/\\/localhost:\\d+)/)\n      if (match) {\n        child.unref()\n        const url = match[1]!\n        const port = parseInt(new URL(url).port, 10)\n        resolve({ action: 'started', url, port, pid: child.pid! })\n      }\n    })\n\n    child.on('error', (err) => reject(err))\n    child.on('exit', (code) => {\n      if (!output.includes('VIEWER_URL')) {\n        reject(new Error(`viewer-server exited with code ${code}`))\n      }\n    })\n\n    // Timeout after 10s\n    setTimeout(() => {\n      if (!output.includes('VIEWER_URL')) {\n        child.kill()\n        reject(new Error('viewer-server startup timed out'))\n      }\n    }, 10000)\n  })\n}\n\nexport function runTreeStop(skillRoot: string): TreeStopResult {\n  const info = readServerInfo(skillRoot)\n  if (!info) return { action: 'not_running' }\n\n  if (isProcessAlive(info.pid)) {\n    try {\n      if (process.platform === 'win32') {\n        execSync(`taskkill /pid ${info.pid} /f /t`, { stdio: 'ignore' })\n      } else {\n        process.kill(info.pid, 'SIGTERM')\n      }\n    } catch { /* ignore */ }\n  }\n\n  try { unlinkSync(serverJsonPath(skillRoot)) } catch { /* ignore */ }\n  return { action: 'stopped' }\n}\n",
  "validate.ts": "/**\n * `state validate <script-id> [<save-type>] [--continue]`\n *\n * Six-fold load-time validation (plus a 7th check for continue-game). Writes\n * nothing. Returns a structured JSON diagnostic to be consumed by the LLM\n * via stdout.\n *\n * Error codes:\n *   DANGLING_SCRIPT_REF        — meta.script_ref points to a missing file\n *   STATE_SCHEMA_MISSING       — script has no state_schema block\n *   INITIAL_STATE_MISMATCH     — initial_state field set != schema field set\n *   CONSEQUENCES_UNKNOWN_KEY   — a choice references a key not in schema\n *   SHARED_AXES_INCOMPLETE     — a character lacks the 3 required shared axes\n *   FLAGS_SET_MISMATCH         — script's flags.* keys don't match story flags\n *   FIELD_MISSING              — state.yaml is missing a schema field (continue-only)\n *   FIELD_EXTRA                — state.yaml has a field not in schema\n *   FIELD_TYPE_MISMATCH        — a state value's type differs from schema\n *   MALFORMED                  — any other parse/read error\n */\n\nimport { existsSync, readFileSync } from 'node:fs'\nimport { validateFieldType, type StateSchema } from './schema.js'\nimport { parseScript, type ParsedScript } from './script.js'\nimport {\n  resolveSavePaths,\n  resolveScriptPath,\n  readMetaFile,\n  readStateFile,\n  type SaveType,\n} from './io.js'\n\nexport interface ValidateError {\n  code: string\n  message: string\n  field?: string\n  expected?: unknown\n  actual?: unknown\n}\n\nexport interface ValidateResult {\n  ok: boolean\n  errors: ValidateError[]\n}\n\nexport interface ValidateOptions {\n  /** If provided, runs the 7th check that state.yaml matches schema. */\n  continueGame?: boolean\n  /** Story-level shared axes (bond is implicit). */\n  sharedAxes?: string[]\n  /** Story-level flag name whitelist. */\n  storyFlags?: string[]\n}\n\nexport function runValidate(\n  skillRoot: string,\n  scriptId: string,\n  saveType: SaveType = 'auto',\n  options: ValidateOptions = {}\n): ValidateResult {\n  const errors: ValidateError[] = []\n  const paths = resolveSavePaths(skillRoot, scriptId, saveType)\n\n  // Read meta.yaml\n  if (!existsSync(paths.metaYamlPath)) {\n    return {\n      ok: false,\n      errors: [\n        {\n          code: 'MALFORMED',\n          message: `meta.yaml not found at ${paths.metaYamlPath}`,\n        },\n      ],\n    }\n  }\n\n  let meta\n  try {\n    meta = readMetaFile(paths.metaYamlPath)\n  } catch (err) {\n    return {\n      ok: false,\n      errors: [\n        { code: 'MALFORMED', message: (err as Error).message },\n      ],\n    }\n  }\n\n  // 1. Dangling reference\n  const scriptPath = resolveScriptPath(skillRoot, meta.scriptRef)\n  if (!existsSync(scriptPath)) {\n    return {\n      ok: false,\n      errors: [\n        {\n          code: 'DANGLING_SCRIPT_REF',\n          message: `script file not found: ${scriptPath}`,\n          field: 'script_ref',\n          actual: meta.scriptRef,\n        },\n      ],\n    }\n  }\n\n  // 2. state_schema present + parseable\n  let script: ParsedScript\n  try {\n    const text = readFileSync(scriptPath, 'utf8')\n    const rawJson = JSON.parse(text) as Record<string, unknown>\n    if (!('state_schema' in rawJson) || rawJson.state_schema === null) {\n      return {\n        ok: false,\n        errors: [\n          {\n            code: 'STATE_SCHEMA_MISSING',\n            message: 'script has no state_schema block',\n          },\n        ],\n      }\n    }\n    script = parseScript(text)\n  } catch (err) {\n    return {\n      ok: false,\n      errors: [\n        {\n          code: 'MALFORMED',\n          message: `cannot parse script: ${(err as Error).message}`,\n        },\n      ],\n    }\n  }\n\n  // 3. initial_state field set alignment\n  const schemaKeys = new Set(Object.keys(script.schema))\n  const initKeys = new Set(Object.keys(script.initialState))\n  for (const k of schemaKeys) {\n    if (!initKeys.has(k)) {\n      errors.push({\n        code: 'INITIAL_STATE_MISMATCH',\n        message: `initial_state missing field \"${k}\"`,\n        field: k,\n      })\n    }\n  }\n  for (const k of initKeys) {\n    if (!schemaKeys.has(k)) {\n      errors.push({\n        code: 'INITIAL_STATE_MISMATCH',\n        message: `initial_state has extra field \"${k}\" not in schema`,\n        field: k,\n      })\n    }\n  }\n\n  // 4. consequences sample — scan every choice's keys\n  for (const [sceneId, scene] of script.scenes) {\n    for (const choice of scene.choices) {\n      for (const key of Object.keys(choice.consequences)) {\n        if (!schemaKeys.has(key)) {\n          errors.push({\n            code: 'CONSEQUENCES_UNKNOWN_KEY',\n            message: `scene \"${sceneId}\" choice \"${choice.id}\" references unknown key \"${key}\"`,\n            field: key,\n          })\n        }\n      }\n    }\n  }\n\n  // 5. shared axes completeness — when sharedAxes option is supplied\n  if (options.sharedAxes !== undefined) {\n    const chars = extractCharacters(script.schema)\n    const required = new Set(['bond', ...options.sharedAxes])\n    for (const char of chars) {\n      for (const axis of required) {\n        const key = `affinity.${char}.${axis}`\n        if (!schemaKeys.has(key)) {\n          errors.push({\n            code: 'SHARED_AXES_INCOMPLETE',\n            message: `character \"${char}\" missing shared axis \"${axis}\"`,\n            field: key,\n          })\n        }\n      }\n    }\n  }\n\n  // 6. flags set match\n  if (options.storyFlags !== undefined) {\n    const scriptFlags = new Set<string>()\n    for (const key of schemaKeys) {\n      if (key.startsWith('flags.')) {\n        scriptFlags.add(key.slice('flags.'.length))\n      }\n    }\n    const expected = new Set(options.storyFlags)\n    for (const name of expected) {\n      if (!scriptFlags.has(name)) {\n        errors.push({\n          code: 'FLAGS_SET_MISMATCH',\n          message: `story flag \"${name}\" missing from script state_schema`,\n          field: `flags.${name}`,\n        })\n      }\n    }\n    for (const name of scriptFlags) {\n      if (!expected.has(name)) {\n        errors.push({\n          code: 'FLAGS_SET_MISMATCH',\n          message: `script has extra flag \"${name}\" not in story_spec`,\n          field: `flags.${name}`,\n        })\n      }\n    }\n  }\n\n  // 7. continue-game state.yaml alignment\n  if (options.continueGame) {\n    if (!existsSync(paths.stateYamlPath)) {\n      errors.push({\n        code: 'MALFORMED',\n        message: `state.yaml not found at ${paths.stateYamlPath}`,\n      })\n    } else {\n      try {\n        const parsedState = readStateFile(paths.stateYamlPath)\n        const stateKeys = new Set(Object.keys(parsedState.state))\n        for (const k of schemaKeys) {\n          if (!stateKeys.has(k)) {\n            errors.push({\n              code: 'FIELD_MISSING',\n              message: `state.yaml missing schema field \"${k}\"`,\n              field: k,\n            })\n          }\n        }\n        for (const k of stateKeys) {\n          if (!schemaKeys.has(k)) {\n            errors.push({\n              code: 'FIELD_EXTRA',\n              message: `state.yaml has extra field \"${k}\" not in schema`,\n              field: k,\n            })\n          }\n        }\n        // type checks\n        for (const [key, value] of Object.entries(parsedState.state)) {\n          const field = script.schema[key]\n          if (field === undefined) continue\n          if (!validateFieldType(field, value)) {\n            errors.push({\n              code: 'FIELD_TYPE_MISMATCH',\n              message: `state.yaml field \"${key}\" has wrong type`,\n              field: key,\n              expected: field.type,\n              actual: typeof value,\n            })\n          }\n        }\n      } catch (err) {\n        errors.push({\n          code: 'MALFORMED',\n          message: `cannot parse state.yaml: ${(err as Error).message}`,\n        })\n      }\n    }\n  }\n\n  return { ok: errors.length === 0, errors }\n}\n\nfunction extractCharacters(schema: StateSchema): Set<string> {\n  const out = new Set<string>()\n  for (const key of Object.keys(schema)) {\n    if (key.startsWith('affinity.')) {\n      const rest = key.slice('affinity.'.length)\n      const dot = rest.indexOf('.')\n      if (dot > 0) out.add(rest.slice(0, dot))\n    }\n  }\n  return out\n}\n",
  "viewer-data.ts": "/**\n * Viewer data loading and file watching.\n *\n * Extracted from tree-server.ts — shared between production and dev server modes.\n */\n\nimport { existsSync, readFileSync, watch } from 'node:fs'\nimport { join, dirname } from 'node:path'\nimport { readHistory } from './history.js'\nimport { loadScriptFile } from './script.js'\nimport { resolveScriptPath, resolveSavePaths, readMetaFile } from './io.js'\n\nexport function loadTreeData(skillRoot: string, scriptId: string): Record<string, unknown> {\n  const scriptPath = resolveScriptPath(skillRoot, scriptId)\n  const script = loadScriptFile(scriptPath)\n  const paths = resolveSavePaths(skillRoot, scriptId, 'auto')\n\n  let currentScene = script.firstSceneId\n  let history: string[] = []\n\n  if (existsSync(paths.metaYamlPath)) {\n    try {\n      const meta = readMetaFile(paths.metaYamlPath)\n      currentScene = meta.currentScene\n    } catch { /* use default */ }\n  }\n\n  const historyLogPath = join(dirname(paths.stateYamlPath), 'history.log')\n  if (existsSync(historyLogPath)) {\n    const entries = readHistory(historyLogPath)\n    history = entries.map((e) => `${e.sceneId}:${e.choiceId}`)\n  }\n\n  const rawScenes = (script.raw as Record<string, unknown>).scenes as Record<string, Record<string, unknown>> | undefined\n  const scenes: Record<string, unknown> = {}\n  for (const [id, scene] of script.scenes) {\n    const rawScene = rawScenes?.[id]\n    scenes[id] = {\n      text: scene.text,\n      choices: scene.choices,\n      route: rawScene?.route ?? scene.route,\n      type: rawScene?.type ?? scene.type,\n      routing: rawScene?.routing ?? scene.routing,\n    }\n  }\n\n  const gateScenes: string[] = []\n  for (const [id] of script.scenes) {\n    const rawScene = rawScenes?.[id]\n    if (rawScene?.type === 'affinity_gate') {\n      gateScenes.push(id)\n    }\n  }\n\n  const routeSet = new Set<string>()\n  for (const [_id, scene] of script.scenes) {\n    const rawScene = rawScenes?.[_id]\n    const route = rawScene?.route ?? scene.route\n    if (typeof route === 'string') routeSet.add(route)\n    const routing = rawScene?.routing ?? scene.routing\n    if (Array.isArray(routing)) {\n      for (const r of routing as Array<{ route_id?: string }>) {\n        if (typeof r.route_id === 'string') routeSet.add(r.route_id)\n      }\n    }\n  }\n  const rawRoutes = (script.raw as Record<string, unknown>).routes as string[] | undefined\n  if (Array.isArray(rawRoutes)) {\n    for (const r of rawRoutes) routeSet.add(r)\n  }\n  const routes = [...routeSet]\n\n  const endings: Record<string, { text: string; type: string }> = {}\n  for (const scene of script.scenes.values()) {\n    for (const choice of scene.choices) {\n      if (choice.next && !script.scenes.has(choice.next)) {\n        endings[choice.next] = { text: choice.next, type: 'ending' }\n      }\n    }\n  }\n\n  return { scenes, history, currentScene, endings, scriptId, routes, gateScenes }\n}\n\nexport interface FileWatcher {\n  close: () => void\n}\n\nexport function watchSaveDir(\n  skillRoot: string,\n  scriptId: string,\n  onChange: (data: Record<string, unknown>) => void,\n): FileWatcher {\n  const paths = resolveSavePaths(skillRoot, scriptId, 'auto')\n  const saveDir = dirname(paths.stateYamlPath)\n\n  if (!existsSync(saveDir)) return { close: () => {} }\n\n  const watcher = watch(saveDir, (_eventType, filename) => {\n    if (filename === 'history.log' || filename === 'meta.yaml') {\n      setTimeout(() => {\n        const data = loadTreeData(skillRoot, scriptId)\n        onChange(data)\n      }, 100)\n    }\n  })\n\n  return { close: () => watcher.close() }\n}\n",
  "viewer-server.ts": "/**\n * Viewer HTTP server — standalone service.\n *\n * Production: runs as a detached process, serves static files from\n *   ~/.soulkiller/viewer/ + API endpoints. Spawned by main.ts viewer command.\n *\n * Development: `bun run dev:viewer tree <script-id>` starts vite dev + API.\n *\n * Environment variables (production mode):\n *   SKILL_ROOT — path to the skill directory\n *   VIEWER_VIEW — view name (e.g., \"tree\")\n *   VIEWER_SCRIPT_ID — script id\n */\n\nimport { existsSync, writeFileSync, unlinkSync, mkdirSync } from 'node:fs'\nimport { join, dirname, resolve } from 'node:path'\nimport { homedir } from 'node:os'\nimport { loadTreeData, watchSaveDir } from './viewer-data.js'\n\nconst DEFAULT_PORT = 6677\nconst MAX_PORT_TRIES = 10\nconst IDLE_TIMEOUT_MS = 2 * 60 * 60 * 1000\nconst VIEWER_DIR = join(homedir(), '.soulkiller', 'viewer')\n\n// ── SSE client management ────────────────────────────────────────\nconst sseClients = new Set<ReadableStreamDefaultController<Uint8Array>>()\nlet idleTimer: ReturnType<typeof setTimeout> | null = null\n\nfunction resetIdleTimer(skillRoot: string): void {\n  if (idleTimer) clearTimeout(idleTimer)\n  idleTimer = setTimeout(() => {\n    if (sseClients.size === 0) cleanupAndExit(skillRoot)\n  }, IDLE_TIMEOUT_MS)\n}\n\nfunction broadcastSSE(event: string, data: unknown): void {\n  const payload = `event: ${event}\\ndata: ${JSON.stringify(data)}\\n\\n`\n  const encoded = new TextEncoder().encode(payload)\n  for (const ctrl of sseClients) {\n    try { ctrl.enqueue(encoded) } catch { sseClients.delete(ctrl) }\n  }\n}\n\n// ── Server JSON management ───────────────────────────────────────\nfunction serverJsonPath(skillRoot: string): string {\n  return join(skillRoot, 'runtime', 'tree', 'server.json')\n}\n\nfunction writeServerJson(skillRoot: string, port: number, pid: number, scriptId: string): void {\n  const path = serverJsonPath(skillRoot)\n  const dir = dirname(path)\n  if (!existsSync(dir)) mkdirSync(dir, { recursive: true })\n  writeFileSync(path, JSON.stringify({ port, pid, scriptId }, null, 2), 'utf8')\n}\n\nfunction cleanupAndExit(skillRoot: string): void {\n  try { unlinkSync(serverJsonPath(skillRoot)) } catch { /* ignore */ }\n  process.exit(0)\n}\n\n// ── Data loaders per view ────────────────────────────────────────\ntype DataLoader = (skillRoot: string, scriptId: string) => Record<string, unknown>\n\nconst DATA_LOADERS: Record<string, DataLoader> = {\n  tree: loadTreeData,\n}\n\nexport const AVAILABLE_VIEWS = Object.keys(DATA_LOADERS)\n\n// ── MIME type helper ─────────────────────────────────────────────\nconst MIME_TYPES: Record<string, string> = {\n  '.html': 'text/html; charset=utf-8',\n  '.js': 'application/javascript',\n  '.css': 'text/css',\n  '.json': 'application/json',\n  '.svg': 'image/svg+xml',\n  '.png': 'image/png',\n  '.ico': 'image/x-icon',\n}\n\nfunction getMime(path: string): string {\n  const ext = '.' + path.split('.').pop()\n  return MIME_TYPES[ext] ?? 'application/octet-stream'\n}\n\n// ── API request handler ──────────────────────────────────────────\nasync function handleApiRequest(\n  url: URL,\n  req: Request,\n  skillRoot: string,\n  viewName: string,\n  scriptId: string,\n  boundPort: number,\n): Promise<Response | null> {\n  const loader = DATA_LOADERS[viewName]\n  if (!loader) return null\n\n  if (url.pathname === '/api/data') {\n    const data = loader(skillRoot, scriptId)\n    return new Response(JSON.stringify(data), { headers: { 'Content-Type': 'application/json' } })\n  }\n\n  if (url.pathname === '/api/events') {\n    const stream = new ReadableStream<Uint8Array>({\n      start(controller) {\n        sseClients.add(controller)\n        resetIdleTimer(skillRoot)\n      },\n      cancel(controller) {\n        sseClients.delete(controller)\n        if (sseClients.size === 0) resetIdleTimer(skillRoot)\n      },\n    })\n    return new Response(stream, {\n      headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache', 'Connection': 'keep-alive' },\n    })\n  }\n\n  if (url.pathname === '/api/switch' && req.method === 'POST') {\n    const body = await req.json() as { scriptId: string }\n    const data = loader(skillRoot, body.scriptId)\n    broadcastSSE('switch', data)\n    writeServerJson(skillRoot, boundPort, process.pid, body.scriptId)\n    return Response.json({ ok: true })\n  }\n\n  return null\n}\n\n// ── Production server (runs as detached process) ─────────────────\n\nexport function startServer(skillRoot: string, viewName: string, scriptId: string): void {\n  if (!existsSync(join(VIEWER_DIR, 'index.html'))) {\n    process.stderr.write(`error: ${VIEWER_DIR}/index.html not found.\\nRun \"soulkiller --update\" or reinstall to restore viewer files.\\n`)\n    process.exit(1)\n  }\n\n  let boundPort = DEFAULT_PORT\n\n  for (let i = 0; i < MAX_PORT_TRIES; i++) {\n    const tryPort = DEFAULT_PORT + i\n    try {\n      Bun.serve({\n        port: tryPort,\n        idleTimeout: 0,\n        async fetch(req) {\n          const url = new URL(req.url)\n\n          // API routes\n          const apiResponse = await handleApiRequest(url, req, skillRoot, viewName, scriptId, tryPort)\n          if (apiResponse) return apiResponse\n\n          // Static files from ~/.soulkiller/viewer/\n          const pathname = url.pathname === '/' ? '/index.html' : url.pathname\n          const filePath = join(VIEWER_DIR, pathname)\n          const file = Bun.file(filePath)\n          if (await file.exists()) {\n            return new Response(file, { headers: { 'Content-Type': getMime(pathname) } })\n          }\n\n          // SPA fallback\n          return new Response(Bun.file(join(VIEWER_DIR, 'index.html')), {\n            headers: { 'Content-Type': 'text/html; charset=utf-8' },\n          })\n        },\n      })\n      boundPort = tryPort\n      break\n    } catch {\n      if (i === MAX_PORT_TRIES - 1) {\n        process.stderr.write(`error: failed to bind any port in range ${DEFAULT_PORT}-${DEFAULT_PORT + MAX_PORT_TRIES - 1}\\n`)\n        process.exit(1)\n      }\n    }\n  }\n\n  const treeDir = join(skillRoot, 'runtime', 'tree')\n  if (!existsSync(treeDir)) mkdirSync(treeDir, { recursive: true })\n  writeServerJson(skillRoot, boundPort, process.pid, scriptId)\n\n  watchSaveDir(skillRoot, scriptId, (data) => broadcastSSE('update', data))\n  resetIdleTimer(skillRoot)\n\n  // Signal to parent that we're ready\n  process.stdout.write(`VIEWER_URL http://localhost:${boundPort}\\n`)\n}\n\n// ── Dev server ───────────────────────────────────────────────────\nasync function startDevServer(\n  skillRoot: string,\n  viewName: string,\n  scriptId: string,\n): Promise<void> {\n  const { createServer } = await import('vite')\n\n  const viewerRoot = resolve(process.cwd(), 'packages', 'viewer')\n\n  let apiPort = DEFAULT_PORT\n  for (let i = 0; i < MAX_PORT_TRIES; i++) {\n    const tryPort = DEFAULT_PORT + i\n    try {\n      Bun.serve({\n        port: tryPort,\n        idleTimeout: 0,\n        async fetch(req) {\n          const url = new URL(req.url)\n          const apiResponse = await handleApiRequest(url, req, skillRoot, viewName, scriptId, tryPort)\n          if (apiResponse) return apiResponse\n          return new Response('Not Found', { status: 404 })\n        },\n      })\n      apiPort = tryPort\n      break\n    } catch {\n      if (i === MAX_PORT_TRIES - 1) throw new Error('Failed to bind API port')\n    }\n  }\n\n  watchSaveDir(skillRoot, scriptId, (data) => broadcastSSE('update', data))\n\n  const server = await createServer({\n    root: viewerRoot,\n    server: {\n      proxy: {\n        '/api': { target: `http://localhost:${apiPort}`, changeOrigin: true },\n      },\n    },\n  })\n\n  await server.listen()\n  const viteUrl = server.resolvedUrls?.local?.[0] ?? `http://localhost:${server.config.server.port}`\n\n  process.stdout.write(`VIEWER_URL ${viteUrl}\\n`)\n  process.stdout.write(`API_PORT ${apiPort}\\n`)\n  process.stdout.write(`MODE dev\\n`)\n}\n\n// ── Entry point ──────────────────────────────────────────────────\nif (import.meta.main) {\n  const args = process.argv.slice(2)\n  const mode = process.env.VIEWER_MODE ?? 'dev'\n  const viewName = process.env.VIEWER_VIEW ?? args[0]\n  const scriptId = process.env.VIEWER_SCRIPT_ID ?? args[1]\n\n  if (!viewName || !scriptId) {\n    process.stderr.write(`usage: bun viewer-server.ts <view-name> <script-id>\\navailable views: ${AVAILABLE_VIEWS.join(', ')}\\n`)\n    process.exit(2)\n  }\n\n  if (!AVAILABLE_VIEWS.includes(viewName)) {\n    process.stderr.write(`error: unknown view \"${viewName}\"\\navailable views: ${AVAILABLE_VIEWS.join(', ')}\\n`)\n    process.exit(2)\n  }\n\n  const skillRoot = process.env.SKILL_ROOT ?? process.env.CLAUDE_SKILL_DIR\n  if (!skillRoot) {\n    process.stderr.write('error: SKILL_ROOT or CLAUDE_SKILL_DIR env var required\\n')\n    process.exit(1)\n  }\n\n  if (mode === 'production') {\n    startServer(skillRoot, viewName, scriptId)\n  } else {\n    await startDevServer(skillRoot, viewName, scriptId)\n  }\n}\n",
}
